function todayIsoDate() {
  return new Date().toISOString().slice(0, 10);
}

function addDaysIsoDate(days: number) {
  const date = new Date();
  date.setDate(date.getDate() + days);
  return date.toISOString().slice(0, 10);
}

function formatDate(value: string | null) {
  if (!value) {
    return "No date";
  }

  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(new Date(`${value.slice(0, 10)}T00:00:00`));
}

function formatDateTime(value: string) {
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(new Date(value));
}

function toDateTimeInputValue(value: string) {
  const date = new Date(value);
  const offset = date.getTimezoneOffset() * 60_000;
  return new Date(date.getTime() - offset).toISOString().slice(0, 16);
}

function fromDateTimeInputValue(value: string) {
  return new Date(value).toISOString();
}

function restoreWindowScrollPosition(left: number, top: number) {
  const restore = () => {
    const root = document.documentElement;
    const body = document.body;
    const previousRootScrollBehavior = root.style.scrollBehavior;
    const previousBodyScrollBehavior = body.style.scrollBehavior;

    root.style.scrollBehavior = "auto";
    body.style.scrollBehavior = "auto";
    window.scrollTo({ left, top, behavior: "auto" });
    root.style.scrollBehavior = previousRootScrollBehavior;
    body.style.scrollBehavior = previousBodyScrollBehavior;
  };

  window.requestAnimationFrame(() => {
    window.requestAnimationFrame(() => {
      restore();
      [50, 150, 300, 500, 700, 850, 1000, 1200].forEach((delay) => {
        window.setTimeout(restore, delay);
      });
    });
  });
}

function updateUiPreservingScrollPosition(update: () => void) {
  const scrollLeft = window.scrollX;
  const scrollTop = window.scrollY;

  update();
  restoreWindowScrollPosition(scrollLeft, scrollTop);
}

