function hasUpcomingScheduledEvent(events: ScheduleEventRecord[]) {
  const today = todayIsoDate();
  return events.some(
    (event) => event.status === "scheduled" && event.start_at.slice(0, 10) >= today,
  );
}

function countScheduleEventConflicts(events: ScheduleEventRecord[]) {
  const scheduledEvents = events
    .filter((event) => event.status === "scheduled")
    .map((event) => ({
      id: event.id,
      start: Date.parse(event.start_at),
      end: Date.parse(event.end_at),
    }))
    .filter((event) => Number.isFinite(event.start) && Number.isFinite(event.end))
    .sort((a, b) => a.start - b.start);

  let conflictCount = 0;

  for (let index = 0; index < scheduledEvents.length; index += 1) {
    for (let otherIndex = index + 1; otherIndex < scheduledEvents.length; otherIndex += 1) {
      const current = scheduledEvents[index];
      const next = scheduledEvents[otherIndex];

      if (next.start >= current.end) {
        break;
      }

      if (current.id !== next.id && current.start < next.end && next.start < current.end) {
        conflictCount += 1;
      }
    }
  }

  return conflictCount;
}

function hasSavedJobSchedule(job: JobRecord) {
  return Boolean(getJobScheduledStart(job) || getJobScheduledEnd(job));
}

function formatJobSchedule(job: JobRecord) {
  const scheduledStart = getJobScheduledStart(job);
  const scheduledEnd = getJobScheduledEnd(job);

  if (scheduledStart && scheduledEnd) {
    return `${formatDateTime(scheduledStart)} to ${formatDateTime(scheduledEnd)}`;
  }

  if (scheduledStart) {
    return formatDateTime(scheduledStart);
  }

  if (scheduledEnd) {
    return `Ends ${formatDateTime(scheduledEnd)}`;
  }

  return "Not scheduled";
}

function getJobScheduleSummary(snapshot: CrmSnapshot, job: JobRecord) {
  const savedSchedule = formatJobSchedule(job);

  if (savedSchedule !== "Not scheduled") {
    return savedSchedule;
  }

  const nextEvent =
    getJobScheduleEvents(snapshot, job.id).find(
      (event) => event.status === "scheduled" && event.start_at.slice(0, 10) >= todayIsoDate(),
    ) ?? getJobScheduleEvents(snapshot, job.id)[0];

  return nextEvent ? formatDateTime(nextEvent.start_at) : "Not scheduled";
}

function getJobAssignedEmployeeNames(snapshot: CrmSnapshot, jobId: string) {
  return getJobAssignments(snapshot, jobId)
    .map((assignment) => getEmployeeName(snapshot, assignment.employee_id))
    .filter((name): name is string => Boolean(name));
}

function jobHasCrew(snapshot: CrmSnapshot, job: JobRecord) {
  return (
    Boolean(job.crew_name?.trim()) ||
    getJobAssignments(snapshot, job.id).some(
      (assignment) => assignment.status === "assigned" || assignment.status === "accepted",
    )
  );
}

function getJobCrewLabel(snapshot: CrmSnapshot, job: JobRecord) {
  if (job.crew_name?.trim()) {
    return job.crew_name;
  }

  const names = getJobAssignedEmployeeNames(snapshot, job.id);

  if (names.length === 1) {
    return names[0];
  }

  if (names.length > 1) {
    return `${names.length} assigned`;
  }

  return "Crew needed";
}

function getJobScheduleDateParts(snapshot: CrmSnapshot, job: JobRecord) {
  return [
    getJobScheduledStart(job),
    getJobScheduledEnd(job),
    ...getJobScheduleEvents(snapshot, job.id).map((event) => event.start_at),
  ]
    .filter((value): value is string => Boolean(value))
    .map((value) => value.slice(0, 10));
}

function addDaysToIsoDate(isoDate: string, days: number) {
  const date = new Date(`${isoDate}T00:00:00`);
  date.setDate(date.getDate() + days);

  return date.toISOString().slice(0, 10);
}

function jobMatchesScheduleFilter(
  snapshot: CrmSnapshot,
  job: JobRecord,
  filter: JobScheduleFilter,
) {
  if (filter === "all") {
    return true;
  }

  const scheduleDates = getJobScheduleDateParts(snapshot, job);

  if (filter === "unscheduled") {
    return scheduleDates.length === 0;
  }

  if (filter === "scheduled") {
    return scheduleDates.length > 0;
  }

  const today = todayIsoDate();

  if (filter === "today") {
    return scheduleDates.some((date) => date === today);
  }

  const weekEnd = addDaysToIsoDate(today, 7);

  return scheduleDates.some((date) => date >= today && date <= weekEnd);
}

function buildJobActivityItems(snapshot: CrmSnapshot, job: JobRecord): JobActivityItem[] {
  const items: JobActivityItem[] = [
    {
      id: `job-created-${job.id}`,
      label: "Job created",
      detail: job.title,
      occurredAt: job.created_at,
      meta: getJobTargetName(snapshot, job),
    },
  ];

  if (job.updated_at !== job.created_at) {
    items.push({
      id: `job-updated-${job.id}`,
      label: "Job updated",
      detail: `Current status: ${jobStatusLabel(job.status)}`,
      occurredAt: job.updated_at,
      meta: getJobCrewLabel(snapshot, job),
    });
  }

  getJobScheduleEvents(snapshot, job.id).forEach((event) => {
    items.push({
      id: `schedule-${event.id}`,
      label: `${scheduleEventTypeLabel(event.event_type)} scheduled`,
      detail: event.title,
      occurredAt: event.start_at,
      meta: scheduleEventStatusLabel(event.status),
    });
  });

  getJobNotes(snapshot, job.id).forEach((note) => {
    items.push({
      id: `note-${note.id}`,
      label: "Production note",
      detail: note.note,
      occurredAt: note.created_at,
      meta: "Note",
    });
  });

  getJobTasks(snapshot, job.id).forEach((task) => {
    items.push({
      id: `task-${task.id}`,
      label: "Checklist task",
      detail: task.title,
      occurredAt: task.updated_at,
      meta: jobTaskStatusLabel(task.status),
    });
  });

  getJobMaterials(snapshot, job.id).forEach((material) => {
    items.push({
      id: `material-${material.id}`,
      label: "Material added",
      detail: `${material.quantity} ${material.unit} - ${material.name}`,
      occurredAt: material.created_at,
      meta: "Material",
    });
  });

  getJobAssignments(snapshot, job.id).forEach((assignment) => {
    items.push({
      id: `assignment-${assignment.id}`,
      label: "Crew assignment",
      detail: assignment.title,
      occurredAt: assignment.updated_at || assignment.assigned_date,
      meta: getEmployeeName(snapshot, assignment.employee_id) ?? assignmentStatusLabel(assignment.status),
    });
  });

  getJobInvoices(snapshot, job.id).forEach((invoice) => {
    items.push({
      id: `invoice-${invoice.id}`,
      label: "Invoice linked",
      detail: `${invoice.invoice_number} - ${formatMoney(invoice.total)}`,
      occurredAt: invoice.issue_date,
      meta: invoiceStatusLabel(invoice.status),
    });
  });

  getJobChangeOrders(snapshot, job.id).forEach((changeOrder) => {
    items.push({
      id: `change-order-${changeOrder.id}`,
      label: "Change order",
      detail: `${changeOrder.title} - ${formatMoney(changeOrder.total)}`,
      occurredAt: changeOrder.updated_at,
      meta: changeOrderStatusLabel(changeOrder.status),
    });
  });

  getJobDocuments(snapshot, job).forEach((document) => {
    items.push({
      id: `document-${document.id}`,
      label: "Document linked",
      detail: document.title,
      occurredAt: document.updated_at,
      meta: documentCategoryLabel(document.category),
    });
  });

  getJobPhotos(snapshot, job.id).forEach((photo) => {
    items.push({
      id: `photo-${photo.id}`,
      label: "Photo added",
      detail: photo.caption ?? "Job photo",
      occurredAt: photo.taken_at ?? photo.created_at,
      meta: "Photo",
    });
  });

  return items
    .sort((a, b) => {
      const left = a.occurredAt ? Date.parse(a.occurredAt) : 0;
      const right = b.occurredAt ? Date.parse(b.occurredAt) : 0;

      return right - left;
    })
    .slice(0, 16);
}

function calculateProductionKpis(snapshot: CrmSnapshot) {
  const activeJobs = snapshot.jobs.filter(
    (job) =>
      job.status === "scheduled" ||
      job.status === "in_progress" ||
      job.status === "blocked",
  );
  const jobsWithUpcomingSchedule = activeJobs.filter(
    (job) =>
      hasSavedJobSchedule(job) ||
      hasUpcomingScheduledEvent(getJobScheduleEvents(snapshot, job.id)),
  );
  const jobsWithCrew = activeJobs.filter(
    (job) => job.crew_name || getJobAssignments(snapshot, job.id).length > 0,
  );
  const activeEmployees = snapshot.employees.filter((employee) => employee.is_active);
  const assignedEmployeeIds = new Set(
    snapshot.jobAssignments
      .filter(
        (assignment) =>
          assignment.status === "assigned" || assignment.status === "accepted",
      )
      .map((assignment) => assignment.employee_id),
  );
  const completedAssignments = snapshot.jobAssignments.filter(
    (assignment) => assignment.status === "completed",
  );
  const activeProductionValue = activeJobs.reduce((total, job) => {
    const estimate = job.estimate_id
      ? snapshot.estimates.find((item) => item.id === job.estimate_id)
      : null;

    return total + (job.total || estimate?.total || 0);
  }, 0);
  const productionInvoiceTotal = snapshot.invoices
    .filter((invoice) => invoice.job_id !== null)
    .reduce((total, invoice) => total + invoice.total, 0);
  const productionMaterialSpend = snapshot.materialOrders
    .filter((order) => order.job_id !== null)
    .reduce((total, order) => total + order.total, 0);
  const jobsMissingSchedule = activeJobs.filter(
    (job) =>
      !hasSavedJobSchedule(job) &&
      !hasUpcomingScheduledEvent(getJobScheduleEvents(snapshot, job.id)),
  );
  const jobsMissingCrew = activeJobs.filter(
    (job) => !job.crew_name && getJobAssignments(snapshot, job.id).length === 0,
  );
  const atRiskJobIds = new Set([
    ...activeJobs.filter((job) => job.status === "blocked").map((job) => job.id),
    ...jobsMissingSchedule.map((job) => job.id),
    ...jobsMissingCrew.map((job) => job.id),
  ]);

  return {
    activeJobs,
    scheduledJobs: snapshot.jobs.filter(
      (job) => job.status === "scheduled" || hasSavedJobSchedule(job),
    ),
    inProgressJobs: snapshot.jobs.filter((job) => job.status === "in_progress"),
    blockedJobs: snapshot.jobs.filter((job) => job.status === "blocked"),
    completedJobs: snapshot.jobs.filter(
      (job) => job.status === "completed" || job.status === "closed",
    ),
    scheduleCoverage: activeJobs.length
      ? Math.round((jobsWithUpcomingSchedule.length / activeJobs.length) * 100)
      : 100,
    crewCoverage: activeJobs.length
      ? Math.round((jobsWithCrew.length / activeJobs.length) * 100)
      : 100,
    crewUtilization: activeEmployees.length
      ? Math.round((assignedEmployeeIds.size / activeEmployees.length) * 100)
      : 0,
    assignmentCompletion: snapshot.jobAssignments.length
      ? Math.round((completedAssignments.length / snapshot.jobAssignments.length) * 100)
      : 0,
    activeProductionValue,
    productionProfit: productionInvoiceTotal - productionMaterialSpend,
    jobsMissingSchedule,
    jobsMissingCrew,
    atRiskJobs: activeJobs.filter((job) => atRiskJobIds.has(job.id)),
  };
}

function getChangeOrderTargetName(snapshot: CrmSnapshot, changeOrder: ChangeOrderRecord) {
  return (
    getJobName(snapshot, changeOrder.job_id) ??
    getCustomerName(snapshot, changeOrder.customer_id) ??
    snapshot.estimates.find((estimate) => estimate.id === changeOrder.estimate_id)?.title ??
    "Unassigned"
  );
}

function getDocumentTargetName(snapshot: CrmSnapshot, document: DocumentRecord) {
  return (
    getCustomerName(snapshot, document.customer_id) ??
    getJobName(snapshot, document.job_id) ??
    snapshot.estimates.find((estimate) => estimate.id === document.estimate_id)?.title ??
    snapshot.invoices.find((invoice) => invoice.id === document.invoice_id)
      ?.invoice_number ??
    snapshot.changeOrders.find((changeOrder) => changeOrder.id === document.change_order_id)
      ?.title ??
    "General"
  );
}

function getDocumentAssociationSummary(snapshot: CrmSnapshot, document: DocumentRecord) {
  const job = document.job_id
    ? snapshot.jobs.find((item) => item.id === document.job_id) ?? null
    : null;
  const invoice = document.invoice_id
    ? snapshot.invoices.find((item) => item.id === document.invoice_id) ?? null
    : null;
  const estimate = document.estimate_id
    ? snapshot.estimates.find((item) => item.id === document.estimate_id) ?? null
    : job?.estimate_id
      ? snapshot.estimates.find((item) => item.id === job.estimate_id) ?? null
      : invoice?.estimate_id
        ? snapshot.estimates.find((item) => item.id === invoice.estimate_id) ?? null
        : null;
  const customer =
    (document.customer_id
      ? snapshot.customers.find((item) => item.id === document.customer_id)
      : null) ??
    (job?.customer_id
      ? snapshot.customers.find((item) => item.id === job.customer_id)
      : null) ??
    (estimate?.customer_id
      ? snapshot.customers.find((item) => item.id === estimate.customer_id)
      : null) ??
    (invoice?.customer_id
      ? snapshot.customers.find((item) => item.id === invoice.customer_id)
      : null) ??
    null;
  const lead =
    (job?.lead_id ? snapshot.leads.find((item) => item.id === job.lead_id) : null) ??
    (estimate?.lead_id
      ? snapshot.leads.find((item) => item.id === estimate.lead_id)
      : null);
  const addressParts = customer
    ? [
        customer.property_address,
        customer.city,
        customer.state,
        customer.postal_code,
      ]
    : lead
      ? [lead.property_address, lead.city, lead.state, lead.postal_code]
      : [];

  return {
    customerName: customer?.display_name ?? lead?.contact_name ?? "Unassigned",
    contact: customer?.contact_name ?? lead?.contact_name ?? "No contact",
    email: customer?.email ?? lead?.email ?? "No email",
    phone: customer?.phone ?? lead?.phone ?? "No phone",
    property:
      job?.property_address || addressParts.filter(Boolean).join(", ") || "No property linked",
    jobTitle: job?.title ?? "No job linked",
    source: getDocumentTargetName(snapshot, document),
  };
}

function documentStatusTone(status: DocumentStatus) {
  if (status === "signed") {
    return "green";
  }

  if (status === "ready" || status === "sent") {
    return "blue";
  }

  return "amber";
}

function getSignatureTargetName(snapshot: CrmSnapshot, signature: SignatureRecord) {
  return (
    snapshot.documents.find((document) => document.id === signature.document_id)?.title ??
    snapshot.changeOrders.find(
      (changeOrder) => changeOrder.id === signature.change_order_id,
    )?.title ??
    getCustomerName(snapshot, signature.customer_id) ??
    getEmployeeName(snapshot, signature.employee_id) ??
    "Signature"
  );
}

function getPaymentTargetName(snapshot: CrmSnapshot, payment: PaymentRecord) {
  return (
    snapshot.invoices.find((invoice) => invoice.id === payment.invoice_id)
      ?.invoice_number ??
    getCustomerName(snapshot, payment.customer_id) ??
    "Payment"
  );
}

function getAssociationSummary(
  snapshot: CrmSnapshot,
  {
    customerId,
    leadId,
    estimateId,
  }: {
    customerId?: string | null;
    leadId?: string | null;
    estimateId?: string | null;
  },
) {
  const estimate = estimateId
    ? snapshot.estimates.find((item) => item.id === estimateId)
    : null;
  const customer =
    (customerId
      ? snapshot.customers.find((item) => item.id === customerId)
      : null) ??
    (estimate?.customer_id
      ? snapshot.customers.find((item) => item.id === estimate.customer_id)
      : null);
  const lead =
    (leadId ? snapshot.leads.find((item) => item.id === leadId) : null) ??
    (estimate?.lead_id
      ? snapshot.leads.find((item) => item.id === estimate.lead_id)
      : null);
  const addressParts = customer
    ? [
        customer.property_address,
        customer.city,
        customer.state,
        customer.postal_code,
      ]
    : lead
      ? [lead.property_address, lead.city, lead.state, lead.postal_code]
      : [];
  const address = addressParts.filter(Boolean).join(", ");

  return {
    name: customer?.display_name ?? lead?.contact_name ?? "Unassigned",
    contact: customer?.contact_name ?? lead?.contact_name ?? "No contact",
    phone: customer?.phone ?? lead?.phone ?? "No phone",
    email: customer?.email ?? lead?.email ?? "No email",
    address: address || "No property linked",
    source: customer ? "Customer" : lead ? "Lead" : estimate ? "Estimate" : "Unassigned",
  };
}

function getSmsTargetName(snapshot: CrmSnapshot, message: SmsMessageRecord) {
  return (
    getCustomerName(snapshot, message.customer_id) ??
    getLeadName(snapshot, message.lead_id) ??
    getJobName(snapshot, message.job_id) ??
    snapshot.scheduleEvents.find((event) => event.id === message.schedule_event_id)
      ?.title ??
    snapshot.invoices.find((invoice) => invoice.id === message.invoice_id)
      ?.invoice_number ??
    "General SMS"
  );
}

function buildDefaultSmsBody({
  category,
  companyName,
  targetName,
  event,
  invoice,
  job,
}: {
  category: SmsMessageCategory;
  companyName: string;
  targetName: string;
  event?: ScheduleEventRecord;
  invoice?: InvoiceRecord;
  job?: JobRecord;
}) {
  const optOut = "Reply STOP to opt out.";

  if (category === "appointment_reminder" && event) {
    return `Hi ${targetName}, this is ${companyName}. Reminder: ${event.title} is scheduled for ${formatDateTime(event.start_at)}${event.location ? ` at ${event.location}` : ""}. ${optOut}`;
  }

  if (category === "invoice_reminder" && invoice) {
    return `Hi ${targetName}, ${companyName} invoice ${invoice.invoice_number} has a balance of ${formatMoney(invoice.balance_due)}. Please reply with questions or payment timing. ${optOut}`;
  }

  if (category === "job_update" && job) {
    return `Hi ${targetName}, ${companyName} update for ${job.title}: current status is ${jobStatusLabel(job.status)}. We will keep you posted as production moves forward. ${optOut}`;
  }

  if (category === "weather_delay") {
    return `Hi ${targetName}, this is ${companyName}. Weather may affect today's schedule. Our team is reviewing conditions and will confirm the next update shortly. ${optOut}`;
  }

  if (category === "estimate_follow_up") {
    return `Hi ${targetName}, this is ${companyName}. Following up on your estimate. Reply here with questions or approval and we can help reserve the schedule. ${optOut}`;
  }

  return `Hi ${targetName}, this is ${companyName}. Reply here if you have any questions or need an update from our team. ${optOut}`;
}

function getCaughtErrorMessage(currentError: unknown, fallback: string) {
  if (currentError instanceof Error) {
    return currentError.message;
  }

  if (typeof currentError === "string") {
    return currentError;
  }

  if (currentError && typeof currentError === "object" && "message" in currentError) {
    const message = (currentError as { message?: unknown }).message;

    if (typeof message === "string") {
      return message;
    }
  }

  return fallback;
}

function logCaughtError(label: string, currentError: unknown) {
  console.error(label, {
    error: currentError,
    message: getCaughtErrorMessage(currentError, "Unknown error."),
    stack: currentError instanceof Error ? currentError.stack : undefined,
    cause:
      currentError instanceof Error
        ? (currentError as Error & { cause?: unknown }).cause
        : undefined,
  });
}

async function withTimeout<Result>(
  promise: Promise<Result>,
  timeoutMs: number,
  message: string,
) {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  try {
    return await Promise.race([
      promise,
      new Promise<Result>((_resolve, reject) => {
        timeoutId = setTimeout(() => reject(new Error(message)), timeoutMs);
      }),
    ]);
  } finally {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
  }
}

export function CrmApp() {
  const demoFallbackEnabled = isCrmDemoFallbackEnabled();
  const demoUser = useMemo(
    () =>
      ({
        id: "local-demo-user",
        email: "local@weathertech.demo",
      }) as User,
    [],
  );

  const [client] = useState<SupabaseClient<Database> | null>(() =>
    getSupabaseBrowserClient(),
  );
  const [user, setUser] = useState<User | null>(null);
  const [authReady, setAuthReady] = useState(client === null);
  const [snapshot, setSnapshot] = useState<CrmSnapshot | null>(null);
  const [view, setView] = useState<WorkspaceView>("dashboard");
  const [notice, setNotice] = useState("");
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<ThemeMode>(() => {
    if (typeof window === "undefined") {
      return "light";
    }

    return window.localStorage.getItem("weathertech-theme") === "dark"
      ? "dark"
      : "light";
  });

  useEffect(() => {
    document.documentElement.dataset.theme = theme;
    window.localStorage.setItem("weathertech-theme", theme);
  }, [theme]);

  const handleThemeChange = (nextTheme: ThemeMode) => {
    setTheme(nextTheme);
  };

  const loadSnapshot = useCallback(async (crmClient: CrmClient, showLoading = true) => {
    if (showLoading) {
      setIsLoading(true);
    }
    setError("");

    try {
      const nextSnapshot = await fetchCrmSnapshot(crmClient);
      setSnapshot(nextSnapshot);
    } catch (currentError) {
      logCaughtError("[CRM] CRM snapshot load failed", currentError);

      if (demoFallbackEnabled) {
        setSnapshot(createDemoCrmSnapshot());
        setNotice("Using local demo CRM data because live Supabase CRM is unavailable.");
        return;
      }

      setError(getCaughtErrorMessage(currentError, "Unable to load CRM records."));
    } finally {
      setIsLoading(false);
    }
  }, [demoFallbackEnabled]);

  useEffect(() => {
    if (!client) {
      if (demoFallbackEnabled) {
        setUser(demoUser);
        setSnapshot(createDemoCrmSnapshot());
        setAuthReady(true);
        setIsLoading(false);
        setNotice("Using local demo CRM data because Supabase is not configured.");
      }

      return;
    }

    let isMounted = true;

    withTimeout(
      client.auth.getSession(),
      8000,
      "Supabase session check timed out.",
    )
      .then(({ data }) => {
        if (!isMounted) {
          return;
        }

        const activeUser = data.session?.user ?? null;

        if (activeUser) {
          setUser(activeUser);
          setAuthReady(true);
          void loadSnapshot(client);
        } else if (demoFallbackEnabled) {
          setUser(demoUser);
          setSnapshot(createDemoCrmSnapshot());
          setAuthReady(true);
          setIsLoading(false);
          setNotice("Using local demo CRM data because Supabase sign-in is not ready.");
        } else {
          setUser(null);
          setAuthReady(true);
          setIsLoading(false);
        }
      })
      .catch((sessionError) => {
        console.error("Supabase session check failed:", sessionError);

        if (!isMounted) {
          return;
        }

        if (demoFallbackEnabled) {
          setUser(demoUser);
          setSnapshot(createDemoCrmSnapshot());
          setAuthReady(true);
          setIsLoading(false);
          setNotice("Using local demo CRM data because Supabase auth failed to load.");
        } else {
          setError(
            sessionError instanceof Error
              ? sessionError.message
              : "Unable to load Supabase session.",
          );
          setAuthReady(true);
          setIsLoading(false);
        }
      });

    const { data: listener } = client.auth.onAuthStateChange((_event, session) => {
      const activeUser = session?.user ?? null;

      if (activeUser) {
        setUser(activeUser);
        setAuthReady(true);
        void loadSnapshot(client);
      } else if (demoFallbackEnabled) {
        setUser(demoUser);
        setSnapshot(createDemoCrmSnapshot());
        setAuthReady(true);
        setIsLoading(false);
      } else {
        setUser(null);
        setSnapshot(null);
        setAuthReady(true);
        setIsLoading(false);
      }
    });

    return () => {
      isMounted = false;
      listener.subscription.unsubscribe();
    };
  }, [client, demoFallbackEnabled, demoUser, loadSnapshot]);

  const handleAuthNotice = (message: string) => {
    setNotice(message);
    setError("");
  };

  const handleSignOut = async () => {
    if (!client) {
      return;
    }

    await client.auth.signOut();
    setNotice("Signed out.");
    setView("dashboard");
  };

  const handleDemoSnapshotChange = useCallback(
    (updater: (currentSnapshot: CrmSnapshot) => CrmSnapshot) => {
      setSnapshot((currentSnapshot) =>
        currentSnapshot ? updater(currentSnapshot) : currentSnapshot,
      );
    },
    [],
  );

  if (!authReady) {
    return <LoadingScreen label="Preparing WeatherTech OS" />;
  }

  if (!client && !demoFallbackEnabled) {
    return <SupabaseConfigScreen />;
  }

  if (!user) {
    if (!client) {
      return <LoadingScreen label="Loading local demo workspace" />;
    }

    return (
      <AuthScreen client={client} notice={notice} onNotice={handleAuthNotice} />
    );
  }

  if (error && !snapshot && !isLoading) {
    return (
      <LoadErrorScreen
        message={error}
        onRetry={() => {
          if (client) {
            void loadSnapshot(client);
          } else {
            setSnapshot(createDemoCrmSnapshot());
          }
        }}
        onSignOut={handleSignOut}
      />
    );
  }

  if (!snapshot || isLoading) {
    return <LoadingScreen label="Loading CRM workspace" />;
  }

  const isDemoWorkspace = demoFallbackEnabled && user.id === demoUser.id;

  return (
    <CrmWorkspace
      client={client ?? ({} as CrmClient)}
      isDemoMode={isDemoWorkspace}
      notice={notice}
      error={error}
      snapshot={snapshot}
      user={user}
      view={view}
      theme={theme}
      onViewChange={setView}
      onThemeChange={handleThemeChange}
      onReload={async () => {
        if (client && !isDemoWorkspace) {
          await loadSnapshot(client);
        } else {
          setSnapshot(createDemoCrmSnapshot());
        }
      }}
      onScrollPreservingReload={async () => {
        const scrollLeft = window.scrollX;
        const scrollTop = window.scrollY;

        try {
          if (client && !isDemoWorkspace) {
            await loadSnapshot(client, false);
          } else {
            setSnapshot(createDemoCrmSnapshot());
          }
        } finally {
          restoreWindowScrollPosition(scrollLeft, scrollTop);
        }
      }}
      onDemoSnapshotChange={handleDemoSnapshotChange}
      onSignOut={handleSignOut}
      onNotice={setNotice}
      onError={setError}
    />
  );
}

