function normalizeCrmLookup(value: string | null | undefined) {
  return (value ?? "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim()
    .replace(/\s+/g, " ");
}

function normalizePhoneDigits(value: string | null | undefined) {
  return (value ?? "").replace(/\D/g, "");
}

function crmAddressesLikelyMatch(
  firstAddress: string | null | undefined,
  secondAddress: string | null | undefined,
) {
  const first = normalizeCrmLookup(firstAddress);
  const second = normalizeCrmLookup(secondAddress);

  if (!first || !second) {
    return false;
  }

  if (first === second) {
    return true;
  }

  const firstTokens = [...new Set(first.split(" ").filter(Boolean))];
  const secondTokens = [...new Set(second.split(" ").filter(Boolean))];
  const [shorterTokens, longerTokens] =
    firstTokens.length <= secondTokens.length
      ? [firstTokens, secondTokens]
      : [secondTokens, firstTokens];
  const longerTokenSet = new Set(longerTokens);

  return (
    shorterTokens.length >= 4 &&
    shorterTokens.every((token) => longerTokenSet.has(token))
  );
}

function truncateTimelineText(value: string, maxLength = 120) {
  return value.length > maxLength ? `${value.slice(0, maxLength - 1)}...` : value;
}

function uniqueById<T extends { id: string }>(records: T[]) {
  const seen = new Set<string>();
  return records.filter((record) => {
    if (seen.has(record.id)) {
      return false;
    }

    seen.add(record.id);
    return true;
  });
}

function getRecordAddressKey({
  address,
  city,
  state,
  postalCode,
}: {
  address?: string | null;
  city?: string | null;
  state?: string | null;
  postalCode?: string | null;
}) {
  return normalizeCrmLookup([address, city, state, postalCode].filter(Boolean).join(" "));
}

function formatCustomerPropertyAddress(property: {
  address: string;
  city: string | null;
  state: string | null;
  postalCode: string | null;
}) {
  return [property.address, property.city, property.state, property.postalCode]
    .filter(Boolean)
    .join(", ");
}

function isFutureDateTime(value: string | null) {
  return Boolean(value && new Date(value).getTime() >= Date.now());
}

function isOpenEstimate(estimate: EstimateRecord) {
  return estimate.status === "draft" || estimate.status === "sent";
}

function isActiveJob(job: JobRecord) {
  return !["completed", "closed", "cancelled", "canceled"].includes(job.status);
}

function isOutstandingInvoice(invoice: InvoiceRecord) {
  return invoice.status !== "paid" && invoice.status !== "void" && invoice.balance_due > 0;
}

function getCustomerInitials(customer: CustomerRecord) {
  return (customer.contact_name || customer.display_name)
    .split(/\s+/)
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0])
    .join("")
    .toUpperCase();
}

function recordBelongsToProperty(
  property: Pick<CustomerPropertySummary, "address">,
  address: string | null | undefined,
) {
  return crmAddressesLikelyMatch(property.address, address);
}

function getPropertySourceText(
  customer: CustomerRecord,
  property: Pick<CustomerPropertySummary, "address">,
  related: CustomerRelatedRecords,
) {
  const matchingLeads = related.leads.filter((lead) =>
    recordBelongsToProperty(property, lead.property_address),
  );
  const matchingEstimates = related.estimates.filter((estimate) =>
    recordBelongsToProperty(property, estimate.location),
  );
  const matchingInspections = related.inspections.filter((inspection) =>
    recordBelongsToProperty(property, inspection.property_address),
  );
  const matchingJobs = related.jobs.filter((job) =>
    recordBelongsToProperty(property, job.property_address || job.address),
  );

  return [
    customer.notes,
    ...matchingLeads.flatMap((lead) => [lead.notes, lead.source, lead.service_type]),
    ...matchingEstimates.flatMap((estimate) => [
      estimate.notes,
      estimate.scope_of_work,
      estimate.paint_color_body,
      estimate.paint_color_trim,
      estimate.paint_color_accent,
      estimate.paint_finish ? paintFinishLabel(estimate.paint_finish) : null,
    ]),
    ...matchingInspections.flatMap((inspection) => [
      inspection.notes,
      inspection.internal_notes,
      inspection.purpose,
      ...inspection.findings.flatMap((finding) => [
        finding.area,
        finding.category,
        finding.observation,
        finding.recommendation,
        finding.estimated_remaining_life ?? null,
      ]),
      ...inspection.measurements.flatMap((measurement) => [
        measurement.label,
        measurement.value,
        measurement.unit,
        measurement.notes ?? null,
      ]),
    ]),
    ...matchingJobs.flatMap((job) => [
      job.notes,
      job.scope_of_work,
      job.service_type,
      job.crew_name,
      job.project_manager,
    ]),
  ]
    .filter(Boolean)
    .join("\n");
}

function extractPropertyDetail(sourceText: string, patterns: RegExp[]) {
  for (const pattern of patterns) {
    const match = sourceText.match(pattern);
    const value = match?.[1]?.trim().replace(/[.;]+$/, "");

    if (value) {
      return truncateTimelineText(value, 90);
    }
  }

  return null;
}

function detectPropertyMention(sourceText: string, keywords: RegExp[], fallback: string) {
  return keywords.some((pattern) => pattern.test(sourceText)) ? fallback : "Not documented";
}

function buildCustomerPropertyIntelligence(
  customer: CustomerRecord,
  property: Pick<CustomerPropertySummary, "address">,
  related: CustomerRelatedRecords,
) {
  const sourceText = getPropertySourceText(customer, property, related);
  const normalizedText = sourceText.toLowerCase();
  const matchingEstimates = related.estimates.filter((estimate) =>
    recordBelongsToProperty(property, estimate.location),
  );
  const matchingInspections = related.inspections.filter((inspection) =>
    recordBelongsToProperty(property, inspection.property_address),
  );
  const matchingJobs = related.jobs.filter((job) =>
    recordBelongsToProperty(property, job.property_address || job.address),
  );
  const matchingPhotos = related.photos.filter((photo) => {
    const inspection = photo.inspection_id
      ? related.inspections.find((item) => item.id === photo.inspection_id)
      : null;
    const job = photo.job_id
      ? related.jobs.find((item) => item.id === photo.job_id)
      : null;

    return (
      recordBelongsToProperty(property, inspection?.property_address) ||
      recordBelongsToProperty(property, job?.property_address || job?.address)
    );
  });
  const warrantyDocuments = related.documents.filter(
    (document) => document.category === "warranty",
  );
  const paintingEstimate = matchingEstimates.find(
    (estimate) =>
      estimate.paint_color_body ||
      estimate.paint_color_trim ||
      estimate.paint_color_accent ||
      estimate.paint_finish,
  );
  const colors = [
    paintingEstimate?.paint_color_body ? `Body ${paintingEstimate.paint_color_body}` : null,
    paintingEstimate?.paint_color_trim ? `Trim ${paintingEstimate.paint_color_trim}` : null,
    paintingEstimate?.paint_color_accent ? `Accent ${paintingEstimate.paint_color_accent}` : null,
    paintingEstimate?.paint_finish
      ? `Finish ${paintFinishLabel(paintingEstimate.paint_finish)}`
      : null,
  ].filter(Boolean);

  return {
    roofSystem:
      extractPropertyDetail(sourceText, [
        /roof(?:ing)? system[:\-]\s*([^\n]+)/i,
        /roof type[:\-]\s*([^\n]+)/i,
        /system[:\-]\s*([^\n]+)/i,
      ]) ??
      (matchingJobs.some((job) => job.service_type === "roofing") ||
      matchingInspections.some((inspection) => inspection.service_category === "roofing")
        ? "Roofing history linked"
        : "Not documented"),
    roofAge:
      extractPropertyDetail(sourceText, [
        /roof age[:\-]\s*([^\n]+)/i,
        /roof(?: is)?\s+([0-9]{1,2}\s*(?:years?|yrs?)\s*old)/i,
        /installed[:\-]\s*([^\n]+)/i,
      ]) ?? "Not documented",
    exteriorPaintColors:
      colors.length
        ? colors.join(" · ")
        : extractPropertyDetail(sourceText, [
            /paint colors?[:\-]\s*([^\n]+)/i,
            /exterior colors?[:\-]\s*([^\n]+)/i,
            /body color[:\-]\s*([^\n]+)/i,
          ]) ?? "Not documented",
    hoa:
      customer.customer_type === "hoa"
        ? "HOA account"
        : extractPropertyDetail(sourceText, [/hoa[:\-]\s*([^\n]+)/i]) ??
          detectPropertyMention(normalizedText, [/\bhoa\b/, /homeowners association/], "HOA mentioned"),
    gateCodes:
      extractPropertyDetail(sourceText, [
        /gate code[:\-]\s*([^\n]+)/i,
        /access code[:\-]\s*([^\n]+)/i,
      ]) ?? "Not documented",
    accessInstructions:
      extractPropertyDetail(sourceText, [
        /access instructions?[:\-]\s*([^\n]+)/i,
        /access[:\-]\s*([^\n]+)/i,
        /entry[:\-]\s*([^\n]+)/i,
      ]) ?? "Not documented",
    pets:
      extractPropertyDetail(sourceText, [/pets?[:\-]\s*([^\n]+)/i]) ??
      detectPropertyMention(normalizedText, [/\bdog\b/, /\bcat\b/, /\bpets?\b/], "Pets mentioned"),
    solar:
      extractPropertyDetail(sourceText, [/solar[:\-]\s*([^\n]+)/i]) ??
      detectPropertyMention(normalizedText, [/\bsolar\b/, /pv panels?/], "Solar mentioned"),
    hvacNotes:
      extractPropertyDetail(sourceText, [
        /hvac[:\-]\s*([^\n]+)/i,
        /a\/c[:\-]\s*([^\n]+)/i,
        /air conditioning[:\-]\s*([^\n]+)/i,
      ]) ??
      detectPropertyMention(normalizedText, [/\bhvac\b/, /\ba\/c\b/, /air conditioning/], "HVAC mentioned"),
    warrantyDocuments,
    photos: matchingPhotos.length ? matchingPhotos : related.photos.slice(0, 3),
    inspections: matchingInspections,
  };
}

function buildCustomerPropertySummaries(
  customer: CustomerRecord,
  related: CustomerRelatedRecords,
): CustomerPropertySummary[] {
  const propertyMap = new Map<string, CustomerPropertySummary>();

  const upsertProperty = ({
    address,
    city = null,
    state = null,
    postalCode = null,
    source,
    activeWork = false,
    lastActivity,
  }: {
    address?: string | null;
    city?: string | null;
    state?: string | null;
    postalCode?: string | null;
    source: string;
    activeWork?: boolean;
    lastActivity: string;
  }) => {
    if (!address?.trim()) {
      return;
    }

    const key = getRecordAddressKey({ address, city, state, postalCode });

    if (!key) {
      return;
    }

    const existing = propertyMap.get(key);

    if (existing) {
      propertyMap.set(key, {
        ...existing,
        city: existing.city ?? city,
        state: existing.state ?? state,
        postalCode: existing.postalCode ?? postalCode,
        sources: existing.sources.includes(source)
          ? existing.sources
          : [...existing.sources, source],
        activeWorkCount: existing.activeWorkCount + (activeWork ? 1 : 0),
        lastActivity:
          lastActivity.localeCompare(existing.lastActivity) > 0
            ? lastActivity
            : existing.lastActivity,
      });
      return;
    }

    propertyMap.set(key, {
      id: key,
      address,
      city,
      state,
      postalCode,
      sources: [source],
      activeWorkCount: activeWork ? 1 : 0,
      lastActivity,
      roofSystem: "Not documented",
      roofAge: "Not documented",
      exteriorPaintColors: "Not documented",
      hoa: "Not documented",
      gateCodes: "Not documented",
      accessInstructions: "Not documented",
      pets: "Not documented",
      solar: "Not documented",
      hvacNotes: "Not documented",
      warrantyDocuments: [],
      photos: [],
      inspections: [],
    });
  };

  upsertProperty({
    address: customer.property_address,
    city: customer.city,
    state: customer.state,
    postalCode: customer.postal_code,
    source: "Customer profile",
    activeWork: false,
    lastActivity: customer.updated_at,
  });

  related.leads.forEach((lead) =>
    upsertProperty({
      address: lead.property_address,
      city: lead.city,
      state: lead.state,
      postalCode: lead.postal_code,
      source: "Lead",
      activeWork: lead.status !== "won" && lead.status !== "lost",
      lastActivity: lead.updated_at,
    }),
  );

  related.estimates.forEach((estimate) =>
    upsertProperty({
      address: estimate.location,
      source: "Estimate",
      activeWork: isOpenEstimate(estimate),
      lastActivity: estimate.updated_at,
    }),
  );

  related.inspections.forEach((inspection) =>
    upsertProperty({
      address: inspection.property_address,
      source: "Inspection",
      activeWork: inspection.status !== "completed" && inspection.status !== "canceled",
      lastActivity: inspection.updated_at,
    }),
  );

  related.jobs.forEach((job) =>
    upsertProperty({
      address: job.property_address || job.address,
      source: "Job",
      activeWork: isActiveJob(job),
      lastActivity: job.updated_at,
    }),
  );

  related.scheduleEvents.forEach((event) =>
    upsertProperty({
      address: event.location,
      source: "Calendar",
      activeWork: event.status === "scheduled",
      lastActivity: event.updated_at,
    }),
  );

  return [...propertyMap.values()]
    .map((property) => ({
      ...property,
      ...buildCustomerPropertyIntelligence(customer, property, related),
    }))
    .sort((a, b) => b.lastActivity.localeCompare(a.lastActivity));
}

function recordMatchesCustomerIdentity(
  customer: CustomerRecord,
  record: {
    company_id?: string | null;
    customer_id?: string | null;
    contact_name?: string | null;
    phone?: string | null;
    email?: string | null;
    property_address?: string | null;
    location?: string | null;
    address?: string | null;
  },
) {
  if (record.customer_id === customer.id) {
    return true;
  }

  if (record.company_id && record.company_id !== customer.company_id) {
    return false;
  }

  const customerAddress = normalizeCrmLookup(customer.property_address);
  const recordAddress = normalizeCrmLookup(
    record.property_address ?? record.location ?? record.address,
  );
  const sameAddress = Boolean(customerAddress && customerAddress === recordAddress);
  const customerPhone = normalizePhoneDigits(customer.phone);
  const recordPhone = normalizePhoneDigits(record.phone);
  const samePhone = Boolean(customerPhone && customerPhone === recordPhone);
  const customerEmail = normalizeCrmLookup(customer.email);
  const recordEmail = normalizeCrmLookup(record.email);
  const sameEmail = Boolean(customerEmail && customerEmail === recordEmail);
  const customerName = normalizeCrmLookup(customer.contact_name || customer.display_name);
  const recordName = normalizeCrmLookup(record.contact_name);
  const sameName = Boolean(customerName && customerName === recordName);

  return sameAddress && (samePhone || sameEmail || sameName);
}

function getCustomerRelatedRecords(
  snapshot: CrmSnapshot,
  customer: CustomerRecord,
): CustomerRelatedRecords {
  const leads = uniqueById(
    snapshot.leads.filter((lead) => recordMatchesCustomerIdentity(customer, lead)),
  );
  const leadIds = new Set(leads.map((lead) => lead.id));
  const estimates = uniqueById(
    snapshot.estimates.filter(
      (estimate) =>
        estimate.customer_id === customer.id ||
        (estimate.lead_id !== null && leadIds.has(estimate.lead_id)),
    ),
  );
  const estimateIds = new Set(estimates.map((estimate) => estimate.id));
  const scopes = uniqueById(
    snapshot.scopes.filter(
      (scope) =>
        scope.customer_id === customer.id ||
        (scope.lead_id !== null && leadIds.has(scope.lead_id)) ||
        (scope.estimate_id !== null && estimateIds.has(scope.estimate_id)),
    ),
  );
  const jobs = uniqueById(
    snapshot.jobs.filter(
      (job) =>
        recordMatchesCustomerIdentity(customer, job) ||
        (job.lead_id !== null && leadIds.has(job.lead_id)) ||
        (job.estimate_id !== null && estimateIds.has(job.estimate_id)),
    ),
  );
  const jobIds = new Set(jobs.map((job) => job.id));
  const inspections = uniqueById(
    snapshot.inspections.filter(
      (inspection) =>
        recordMatchesCustomerIdentity(customer, inspection) ||
        (inspection.lead_id !== null && leadIds.has(inspection.lead_id)) ||
        (inspection.estimate_id !== null && estimateIds.has(inspection.estimate_id)) ||
        (inspection.job_id !== null && jobIds.has(inspection.job_id)),
    ),
  );
  const inspectionIds = new Set(inspections.map((inspection) => inspection.id));
  const invoices = uniqueById(
    snapshot.invoices.filter(
      (invoice) =>
        invoice.customer_id === customer.id ||
        (invoice.job_id !== null && jobIds.has(invoice.job_id)) ||
        (invoice.estimate_id !== null && estimateIds.has(invoice.estimate_id)),
    ),
  );
  const invoiceIds = new Set(invoices.map((invoice) => invoice.id));
  const photos = uniqueById(
    snapshot.jobPhotos.filter(
      (photo) =>
        photo.customer_id === customer.id ||
        (photo.job_id !== null && jobIds.has(photo.job_id)) ||
        (photo.estimate_id !== null && estimateIds.has(photo.estimate_id)) ||
        (photo.inspection_id !== null && inspectionIds.has(photo.inspection_id)),
    ),
  );
  const documents = uniqueById(
    snapshot.documents.filter(
      (document) =>
        document.customer_id === customer.id ||
        (document.job_id !== null && jobIds.has(document.job_id)) ||
        (document.estimate_id !== null && estimateIds.has(document.estimate_id)) ||
        (document.invoice_id !== null && invoiceIds.has(document.invoice_id)),
    ),
  );
  const scheduleEvents = uniqueById(
    snapshot.scheduleEvents.filter(
      (event) =>
        event.customer_id === customer.id ||
        (event.lead_id !== null && leadIds.has(event.lead_id)) ||
        (event.job_id !== null && jobIds.has(event.job_id)),
    ),
  );

  return {
    leads,
    estimates,
    scopes,
    inspections,
    jobs,
    invoices,
    photos,
    documents,
    scheduleEvents,
  };
}

function communicationItemMatchesCustomer(
  customer: CustomerRecord,
  related: CustomerRelatedRecords,
  item: UnifiedInboxItem,
) {
  if (item.customerId !== customer.id && item.companyId !== customer.company_id) {
    return false;
  }

  const leadIds = new Set(related.leads.map((lead) => lead.id));
  const customerPhone = normalizePhoneDigits(customer.phone);
  const itemPhone = normalizePhoneDigits(item.phone);
  const customerEmail = normalizeCrmLookup(customer.email);
  const itemEmail = normalizeCrmLookup(item.email);

  return Boolean(
    item.customerId === customer.id ||
      (item.leadId && leadIds.has(item.leadId)) ||
      (customerPhone && itemPhone && customerPhone === itemPhone) ||
      (customerEmail && itemEmail && customerEmail === itemEmail),
  );
}

function getCustomerCommunicationItems(
  snapshot: CrmSnapshot,
  companyMap: Map<string, CompanyRecord>,
  customer: CustomerRecord,
  related: CustomerRelatedRecords,
) {
  return buildUnifiedInboxItems(snapshot, companyMap).filter((item) =>
    communicationItemMatchesCustomer(customer, related, item),
  );
}

function buildCustomerSearchText(
  snapshot: CrmSnapshot,
  companyMap: Map<string, CompanyRecord>,
  customer: CustomerRecord,
) {
  const related = getCustomerRelatedRecords(snapshot, customer);
  const company = companyMap.get(customer.company_id);
  const properties = buildCustomerPropertySummaries(customer, related);
  const communicationItems = getCustomerCommunicationItems(
    snapshot,
    companyMap,
    customer,
    related,
  );

  return [
    customer.id,
    customer.display_name,
    customer.contact_name,
    customer.phone,
    normalizePhoneDigits(customer.phone),
    customer.email,
    customer.property_address,
    customer.city,
    customer.state,
    customer.postal_code,
    customer.notes,
    company?.name,
    company?.short_name,
    customerStatusLabel(customer.status),
    customerTypeLabel(customer.customer_type),
    ...properties.flatMap((property) => [
      property.address,
      property.city,
      property.state,
      property.postalCode,
      formatCustomerPropertyAddress(property),
      ...property.sources,
    ]),
    ...related.leads.flatMap((lead) => [
      lead.id,
      lead.contact_name,
      lead.phone,
      normalizePhoneDigits(lead.phone),
      lead.email,
      lead.property_address,
      lead.city,
      lead.state,
      lead.postal_code,
      lead.source,
      lead.status,
      statusLabel(lead.status),
      pipelineStageLabel(lead.pipeline_stage),
    ]),
    ...related.estimates.flatMap((estimate) => [
      estimate.id,
      estimate.title,
      estimate.business,
      estimate.location,
      estimate.service_type,
      estimateStatusLabel(estimate.status),
    ]),
    ...related.scopes.flatMap((scope) => [
      scope.id,
      scope.title,
      scopeCategoryLabels[scope.category],
      scopeStatusLabel(scope.status),
    ]),
    ...related.inspections.flatMap((inspection) => [
      inspection.id,
      inspection.title,
      inspection.property_address,
      inspection.assigned_inspector,
      inspection.inspection_type,
      inspection.service_category,
      inspectionStatusLabel(inspection.status),
    ]),
    ...related.jobs.flatMap((job) => [
      job.id,
      job.title,
      job.crew_name,
      job.project_manager,
      job.property_address,
      job.address,
      job.business,
      job.location,
      jobStatusLabel(job.status),
    ]),
    ...related.invoices.flatMap((invoice) => [
      invoice.id,
      invoice.invoice_number,
      invoice.title,
      invoiceStatusLabel(invoice.status),
    ]),
    ...related.scheduleEvents.flatMap((event) => [
      event.id,
      event.title,
      event.location,
      scheduleEventTypeLabel(event.event_type),
      scheduleEventStatusLabel(event.status),
    ]),
    ...related.documents.flatMap((document) => [
      document.id,
      document.title,
      documentCategoryLabel(document.category),
      documentStatusLabel(document.status),
    ]),
    ...related.photos.flatMap((photo) => [
      photo.id,
      photo.caption,
      photo.label,
      photo.file_path,
      photo.is_customer_visible ? "customer visible photo" : "internal photo",
    ]),
    ...communicationItems.flatMap((item) => [
      item.customerName,
      item.contact,
      item.phone,
      normalizePhoneDigits(item.phone),
      item.email,
      item.sourceLabel,
      item.sourceAccount,
      communicationChannelLabels[item.channel],
      item.status,
      item.summary,
    ]),
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();
}

function findPotentialCustomerDuplicates(
  customers: CustomerRecord[],
  input: CustomerInput,
  excludeCustomerId?: string,
) {
  const inputAddress = normalizeCrmLookup(input.property_address);
  const inputPhone = normalizePhoneDigits(input.phone);
  const inputEmail = normalizeCrmLookup(input.email);
  const inputName = normalizeCrmLookup(input.contact_name || input.display_name);

  return customers
    .filter(
      (customer) =>
        customer.id !== excludeCustomerId && customer.company_id === input.company_id,
    )
    .map((customer) => {
      const reasons: string[] = [];
      const customerAddress = normalizeCrmLookup(customer.property_address);
      const customerPhone = normalizePhoneDigits(customer.phone);
      const customerEmail = normalizeCrmLookup(customer.email);
      const customerName = normalizeCrmLookup(
        customer.contact_name || customer.display_name,
      );

      if (crmAddressesLikelyMatch(inputAddress, customerAddress)) {
        reasons.push("same service address");
      }

      if (
        inputEmail &&
        customerEmail &&
        inputEmail === customerEmail &&
        (!inputName || !customerName || inputName === customerName)
      ) {
        reasons.push("same email");
      }

      if (
        inputPhone &&
        customerPhone &&
        inputPhone === customerPhone &&
        (!inputName || !customerName || inputName === customerName)
      ) {
        reasons.push("same phone");
      }

      return { customer, reasons };
    })
    .filter((match) => match.reasons.length > 0);
}

function findPotentialLeadDuplicate(
  leads: LeadRecord[],
  input: {
    company_id: string;
    contact_name: string;
    phone?: string | null;
    email?: string | null;
    property_address: string;
  },
) {
  const inputAddress = normalizeCrmLookup(input.property_address);
  const inputPhone = normalizePhoneDigits(input.phone);
  const inputEmail = normalizeCrmLookup(input.email);
  const inputName = normalizeCrmLookup(input.contact_name);

  return leads.find((lead) => {
    if (lead.company_id !== input.company_id || lead.status === "lost") {
      return false;
    }

    const leadAddress = normalizeCrmLookup(lead.property_address);
    const sameAddress = crmAddressesLikelyMatch(inputAddress, leadAddress);
    const samePhone = Boolean(inputPhone && normalizePhoneDigits(lead.phone) === inputPhone);
    const sameEmail = Boolean(inputEmail && normalizeCrmLookup(lead.email) === inputEmail);
    const sameName = Boolean(inputName && normalizeCrmLookup(lead.contact_name) === inputName);

    return sameAddress && (samePhone || sameEmail || sameName);
  });
}

function getLeadDuplicateFingerprint(input: {
  company_id: string;
  contact_name: string;
  phone?: string | null;
  email?: string | null;
  property_address: string;
}) {
  return [
    input.company_id,
    normalizeCrmLookup(input.property_address),
    normalizePhoneDigits(input.phone),
    normalizeCrmLookup(input.email),
    normalizeCrmLookup(input.contact_name),
  ].join("|");
}

function buildCustomerTimelineItems(
  customer: CustomerRecord,
  related: CustomerRelatedRecords,
  communicationItems: UnifiedInboxItem[] = [],
): CustomerTimelineItem[] {
  const items: CustomerTimelineItem[] = [
    {
      id: `customer-created-${customer.id}`,
      label: "Customer created",
      description: customer.display_name,
      occurredAt: customer.created_at,
      user: "WeatherTech OS",
      icon: Users,
      tone: "slate",
      kind: "profile",
    },
  ];

  if (customer.updated_at !== customer.created_at) {
    items.push({
      id: `customer-updated-${customer.id}`,
      label: "Customer status updated",
      description: `${customerStatusLabel(customer.status)} - ${customerTypeLabel(
        customer.customer_type,
      )}`,
      occurredAt: customer.updated_at,
      user: "CRM",
      icon: Pencil,
      tone: customer.status === "inactive" ? "amber" : "blue",
      kind: "profile",
    });
  }

  if (customer.notes) {
    items.push({
      id: `customer-note-${customer.id}`,
      label: "Internal note",
      description: truncateTimelineText(customer.notes),
      occurredAt: customer.updated_at,
      user: "Team",
      icon: MessageSquare,
      tone: "amber",
      kind: "note",
    });
  }

  related.leads.forEach((lead) => {
    items.push({
      id: `lead-${lead.id}`,
      label: getLeadTimelineLabel(lead),
      description: `${lead.contact_name} - ${lead.source} - ${pipelineStageLabel(
        lead.pipeline_stage,
      )}`,
      occurredAt: lead.created_at,
      user: "CRM",
      icon: UserRound,
      tone: "blue",
      kind: "lead",
    });

    if (lead.updated_at !== lead.created_at) {
      items.push({
        id: `lead-status-${lead.id}`,
        label: "Lead status changed",
        description: `${statusLabel(lead.status)} - ${pipelineStageLabel(
          lead.pipeline_stage,
        )}`,
        occurredAt: lead.updated_at,
        user: lead.created_by ?? "CRM",
        icon: ArrowUp,
        tone: lead.status === "won" ? "green" : lead.status === "lost" ? "amber" : "blue",
        kind: "lead",
      });
    }
  });

  related.estimates.forEach((estimate) => {
    items.push({
      id: `estimate-created-${estimate.id}`,
      label: "Estimate created",
      description: `${estimate.title} - ${formatMoney(estimate.total)}`,
      occurredAt: estimate.created_at,
      user: "Estimating",
      icon: Calculator,
      tone: estimate.status === "approved" ? "green" : "blue",
      kind: "estimate",
    });

    if (estimate.updated_at !== estimate.created_at) {
      items.push({
        id: `estimate-revised-${estimate.id}`,
        label: "Estimate revised",
        description: `${estimateStatusLabel(estimate.status)} - ${formatMoney(
          estimate.total,
        )}`,
        occurredAt: estimate.updated_at,
        user: "Estimating",
        icon: Pencil,
        tone: estimate.status === "approved" ? "green" : "blue",
        kind: "estimate",
      });
    }
  });

  related.scopes.forEach((scope) => {
    items.push({
      id: `scope-${scope.id}`,
      label: "Scope prepared",
      description: `${scope.title} - ${scopeStatusLabel(scope.status)}`,
      occurredAt: scope.updated_at,
      user: "Scopes",
      icon: WandSparkles,
      tone: scope.status === "approved" ? "green" : "purple",
      kind: "estimate",
    });
  });

  related.inspections.forEach((inspection) => {
    items.push({
      id: `inspection-${inspection.id}`,
      label: "Inspection",
      description: `${inspection.title} - ${inspectionStatusLabel(inspection.status)}`,
      occurredAt: inspection.updated_at,
      user: inspection.assigned_inspector ?? "Production",
      icon: ClipboardList,
      tone: inspection.status === "completed" ? "green" : "purple",
      kind: "inspection",
    });

    if (inspection.completed_at) {
      items.push({
        id: `inspection-completed-${inspection.id}`,
        label: "Inspection completed",
        description: inspection.outcome
          ? inspectionOutcomeLabel(inspection.outcome)
          : "Inspection marked complete",
        occurredAt: inspection.completed_at,
        user: inspection.assigned_inspector ?? "Production",
        icon: CheckCircle2,
        tone: "green",
        kind: "inspection",
      });
    }

    if (inspection.internal_notes) {
      items.push({
        id: `inspection-internal-note-${inspection.id}`,
        label: "Inspection internal note",
        description: truncateTimelineText(inspection.internal_notes),
        occurredAt: inspection.updated_at,
        user: inspection.assigned_inspector ?? "Production",
        icon: MessageSquare,
        tone: "amber",
        kind: "note",
      });
    }
  });

  related.jobs.forEach((job) => {
    items.push({
      id: `job-created-${job.id}`,
      label: "Job created",
      description: `${job.title} - ${jobStatusLabel(job.status)}`,
      occurredAt: job.created_at,
      user: job.project_manager ?? job.crew_name ?? "Production",
      icon: Building2,
      tone: isActiveJob(job) ? "blue" : "green",
      kind: "job",
    });

    if (job.status === "completed" || job.status === "closed") {
      items.push({
        id: `job-completed-${job.id}`,
        label: "Job completed",
        description: job.title,
        occurredAt: job.end_date ?? job.updated_at,
        user: job.project_manager ?? job.crew_name ?? "Production",
        icon: CheckCircle2,
        tone: "green",
        kind: "job",
      });
    } else if (job.updated_at !== job.created_at) {
      items.push({
        id: `job-status-${job.id}`,
        label: "Job status changed",
        description: `${job.title} - ${jobStatusLabel(job.status)}`,
        occurredAt: job.updated_at,
        user: job.project_manager ?? job.crew_name ?? "Production",
        icon: ArrowUp,
        tone: job.status === "blocked" ? "amber" : "blue",
        kind: "job",
      });
    }
  });

  related.scheduleEvents.forEach((event) => {
    const upcoming = isFutureDateTime(event.start_at) && event.status === "scheduled";

    items.push({
      id: `schedule-${event.id}`,
      label: upcoming ? "Upcoming appointment" : scheduleEventTypeLabel(event.event_type),
      description: `${event.title} - ${formatDateTime(event.start_at)}`,
      occurredAt: event.start_at,
      user: "Scheduler",
      icon: CalendarClock,
      tone: upcoming ? "purple" : event.status === "completed" ? "green" : "slate",
      kind: "calendar",
    });
  });

  related.invoices.forEach((invoice) => {
    items.push({
      id: `invoice-${invoice.id}`,
      label: "Invoice",
      description: `${invoice.invoice_number} - ${formatMoney(invoice.balance_due)} due`,
      occurredAt: invoice.updated_at,
      user: "Financial",
      icon: ReceiptText,
      tone: invoice.status === "paid" ? "green" : "amber",
      kind: "invoice",
    });
  });

  related.documents.forEach((document) => {
    items.push({
      id: `document-${document.id}`,
      label: "Document",
      description: `${document.title} - ${documentCategoryLabel(document.category)}`,
      occurredAt: document.updated_at,
      user: "Documents",
      icon: FileText,
      tone: "slate",
      kind: "document",
    });
  });

  related.photos.forEach((photo) => {
    items.push({
      id: `photo-${photo.id}`,
      label: "Photo",
      description: photo.caption ?? photo.label ?? "Jobsite photo",
      occurredAt: photo.taken_at ?? photo.created_at,
      user: photo.is_customer_visible ? "Field - customer visible" : "Field - internal",
      icon: Camera,
      tone: photo.is_customer_visible ? "green" : "slate",
      kind: "photo",
    });
  });

  communicationItems.forEach((item) => {
    items.push({
      id: `communication-${item.id}`,
      label: `${getCommunicationDirectionLabel(item.direction)} ${communicationChannelLabels[
        item.channel
      ].toLowerCase()}`,
      description: truncateTimelineText(item.summary),
      occurredAt: item.createdAt,
      user: item.sourceLabel,
      icon: item.channel === "email" ? Mail : item.channel === "sms" ? Phone : MessageSquare,
      tone: item.isFailed || item.isUnassigned ? "amber" : "blue",
      kind: "communication",
    });
  });

  return items.sort((a, b) => b.occurredAt.localeCompare(a.occurredAt));
}

function getCustomerLifetimeRevenue(related: CustomerRelatedRecords) {
  const invoiceRevenue = related.invoices.reduce((total, invoice) => total + invoice.total, 0);

  if (invoiceRevenue > 0) {
    return invoiceRevenue;
  }

  return related.jobs
    .filter((job) => job.status === "completed" || job.status === "closed")
    .reduce((total, job) => total + job.total, 0);
}

function getCustomerWarrantyStatus(related: CustomerRelatedRecords) {
  const warrantyDocuments = related.documents.filter(
    (document) => document.category === "warranty",
  );
  const completedJobs = related.jobs.filter(
    (job) => job.status === "completed" || job.status === "closed",
  );

  if (warrantyDocuments.length) {
    return {
      label: "Warranty documented",
      detail: `${warrantyDocuments.length} warranty ${
        warrantyDocuments.length === 1 ? "document" : "documents"
      } linked`,
      tone: "green" as const,
    };
  }

  if (completedJobs.length) {
    return {
      label: "Needs warranty packet",
      detail: "Completed work exists without a linked warranty document",
      tone: "amber" as const,
    };
  }

  return {
    label: "Not started",
    detail: "Warranty will become active after completed work is documented",
    tone: "blue" as const,
  };
}

function getCustomerPrimaryPhoto(related: CustomerRelatedRecords) {
  return (
    related.photos.find((photo) => photo.is_customer_visible) ??
    related.photos[0] ??
    null
  );
}

function getCustomerLastCommunication(items: UnifiedInboxItem[]) {
  return items
    .slice()
    .sort((a, b) => b.createdAt.localeCompare(a.createdAt))[0] ?? null;
}

function getCustomerNextAppointment(related: CustomerRelatedRecords) {
  return related.scheduleEvents
    .filter((event) => event.status === "scheduled" && isFutureDateTime(event.start_at))
    .sort((a, b) => a.start_at.localeCompare(b.start_at))[0] ?? null;
}

function getLeadTimelineLabel(lead: LeadRecord) {
  const source = lead.source.toLowerCase();

  if (source.includes("website")) {
    return "Website inquiry";
  }

  if (source.includes("yelp")) {
    return "Yelp inquiry";
  }

  return "Lead created";
}

function CustomersView({
  client,
  snapshot,
  companyMap,
  onReload,
  onNotice,
  onError,
  onViewChange,
}: CustomersViewProps) {
  const [selectedCustomerId, setSelectedCustomerId] = useState(
    snapshot.customers[0]?.id ?? "",
  );
  const [search, setSearch] = useState("");
  const [companyFilter, setCompanyFilter] = useState<CompanyScopeId>("all");
  const [statusFilter, setStatusFilter] = useState<CustomerStatus | "all">("all");
  const [typeFilter, setTypeFilter] = useState<CustomerType | "all">("all");
  const [isCreatingCustomer, setIsCreatingCustomer] = useState(false);
  const [isUpdatingCustomer, setIsUpdatingCustomer] = useState(false);
  const customerNotesRef = useRef<HTMLTextAreaElement | null>(null);

  const filteredCustomers = useMemo(() => {
    const query = search.trim().toLowerCase();

    return snapshot.customers.filter((customer) => {
      const searchableText = buildCustomerSearchText(snapshot, companyMap, customer);

      return (
        (!query || searchableText.includes(query)) &&
        (companyFilter === "all" || customer.company_id === companyFilter) &&
        (statusFilter === "all" || customer.status === statusFilter) &&
        (typeFilter === "all" || customer.customer_type === typeFilter)
      );
    });
  }, [companyFilter, companyMap, search, snapshot, statusFilter, typeFilter]);

  const {
    page: customerPage,
    pageCount: customerPageCount,
    setPage: setCustomerPage,
    pagedItems: pagedCustomers,
  } = usePagination(filteredCustomers);

  const selectedCustomer =
    snapshot.customers.find((customer) => customer.id === selectedCustomerId) ??
    filteredCustomers[0] ??
    snapshot.customers[0];
  const customerFilterSummary = `${filteredCustomers.length} of ${snapshot.customers.length} customers`;

  useEffect(() => {
    setCustomerPage(1);
  }, [companyFilter, search, setCustomerPage, statusFilter, typeFilter]);

  useEffect(() => {
    if (
      filteredCustomers.length &&
      !filteredCustomers.some((customer) => customer.id === selectedCustomerId)
    ) {
      setSelectedCustomerId(filteredCustomers[0].id);
    }
  }, [filteredCustomers, selectedCustomerId]);

  const handleCreateCustomer = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    if (isCreatingCustomer) {
      return;
    }

    const form = event.currentTarget;
    onError("");

    const formData = new FormData(form);
    const input: CustomerInput = {
      company_id: getFormString(formData, "company_id", snapshot.companies[0]?.id),
      display_name: getFormString(formData, "display_name"),
      contact_name: getFormString(formData, "contact_name"),
      phone: getOptionalFormString(formData, "phone"),
      email: getOptionalFormString(formData, "email"),
      property_address: getFormString(formData, "property_address"),
      city: getOptionalFormString(formData, "city"),
      state: getFormString(formData, "state", "AZ"),
      postal_code: getOptionalFormString(formData, "postal_code"),
      customer_type: getFormString(formData, "customer_type", "homeowner") as CustomerType,
      status: getFormString(formData, "status", "active") as CustomerStatus,
      notes: getOptionalFormString(formData, "notes"),
    };

    if (!input.company_id || !input.display_name || !input.contact_name || !input.property_address) {
      onError("Customer company, name, contact, and property address are required.");
      return;
    }

    const duplicates = findPotentialCustomerDuplicates(snapshot.customers, input);

    if (duplicates.length) {
      onError(
        `Possible duplicate customer: ${duplicates[0].customer.display_name} already has ${duplicates[0].reasons.join(
          " and ",
        )}. Review the existing customer before creating another.`,
      );
      return;
    }

    try {
      setIsCreatingCustomer(true);
      await createCustomer(client, input);
      form.reset();
      await onReload();
      onNotice("Customer created.");
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to create customer."));
    } finally {
      setIsCreatingCustomer(false);
    }
  };

  const handleUpdateCustomer = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    if (!selectedCustomer || isUpdatingCustomer) {
      return;
    }

    const formData = new FormData(event.currentTarget);
    const updates: CustomerInput = {
      company_id: getFormString(formData, "company_id", selectedCustomer.company_id),
      display_name: getFormString(formData, "display_name", selectedCustomer.display_name),
      contact_name: getFormString(formData, "contact_name", selectedCustomer.contact_name),
      phone: getOptionalFormString(formData, "phone"),
      email: getOptionalFormString(formData, "email"),
      property_address: getFormString(
        formData,
        "property_address",
        selectedCustomer.property_address,
      ),
      city: getOptionalFormString(formData, "city"),
      state: getFormString(formData, "state", selectedCustomer.state || "AZ"),
      postal_code: getOptionalFormString(formData, "postal_code"),
      status: getFormString(formData, "status", selectedCustomer.status) as CustomerStatus,
      customer_type: getFormString(
        formData,
        "customer_type",
        selectedCustomer.customer_type,
      ) as CustomerType,
      notes: getOptionalFormString(formData, "notes"),
    };

    if (!updates.display_name || !updates.contact_name || !updates.property_address) {
      onError("Customer name, contact, and property address are required.");
      return;
    }

    const duplicates = findPotentialCustomerDuplicates(
      snapshot.customers,
      updates,
      selectedCustomer.id,
    );

    if (duplicates.length) {
      onError(
        `Possible duplicate customer: ${duplicates[0].customer.display_name} already has ${duplicates[0].reasons.join(
          " and ",
        )}. Review the existing customer before saving.`,
      );
      return;
    }

    try {
      setIsUpdatingCustomer(true);
      await updateCustomer(client, selectedCustomer.id, updates);
      await onReload();
      onNotice("Customer updated.");
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to update customer."));
    } finally {
      setIsUpdatingCustomer(false);
    }
  };

  const handleFocusCustomerNotes = () => {
    customerNotesRef.current?.scrollIntoView({ behavior: "smooth", block: "center" });
    customerNotesRef.current?.focus();
  };

  return (
    <div className="grid gap-5 2xl:grid-cols-[minmax(0,1fr)_minmax(420px,0.95fr)]">
      <section className="rounded-lg border border-slate-200 bg-white shadow-sm">
        <div className="border-b border-slate-200 p-5">
          <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
            <div>
              <h2 className="text-xl font-bold text-slate-950">
                Customer management
              </h2>
              <p className="mt-1 text-sm text-slate-500">
                Profiles, contacts, properties, and account status.
              </p>
            </div>
            <div className="relative">
              <Search className="pointer-events-none absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
              <input
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                aria-label="Search customers"
                data-testid="customers-search"
                className="w-full rounded-md border border-slate-300 py-2 pl-9 pr-3 text-sm outline-none transition focus:border-sky-500 focus:ring-2 focus:ring-sky-100 sm:w-80"
                placeholder="Search customers"
              />
            </div>
          </div>
          <div className="mt-4 grid gap-3 rounded-lg border border-slate-200 bg-slate-50 p-3 md:grid-cols-2 xl:grid-cols-[1fr_1fr_1fr_auto] xl:items-end">
            <label className="grid gap-1 text-xs font-semibold uppercase text-slate-500">
              Company
              <select
                value={companyFilter}
                onChange={(event) => setCompanyFilter(event.target.value as CompanyScopeId)}
                data-testid="customers-company-filter"
                className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-medium normal-case text-slate-700"
              >
                <option value="all">All companies</option>
                {snapshot.companies.map((company) => (
                  <option key={company.id} value={company.id}>
                    {company.name}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase text-slate-500">
              Status
              <select
                value={statusFilter}
                onChange={(event) => setStatusFilter(event.target.value as CustomerStatus | "all")}
                data-testid="customers-status-filter"
                className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-medium normal-case text-slate-700"
              >
                <option value="all">All statuses</option>
                {customerStatuses.map((status) => (
                  <option key={status.value} value={status.value}>
                    {status.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-xs font-semibold uppercase text-slate-500">
              Type
              <select
                value={typeFilter}
                onChange={(event) => setTypeFilter(event.target.value as CustomerType | "all")}
                data-testid="customers-type-filter"
                className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-medium normal-case text-slate-700"
              >
                <option value="all">All types</option>
                {customerTypes.map((type) => (
                  <option key={type.value} value={type.value}>
                    {type.label}
                  </option>
                ))}
              </select>
            </label>
            <div className="flex flex-wrap items-center justify-between gap-2 xl:justify-end">
              <span className="text-sm font-semibold text-slate-600">
                {customerFilterSummary}
              </span>
              <button
                type="button"
                onClick={() => {
                  setSearch("");
                  setCompanyFilter("all");
                  setStatusFilter("all");
                  setTypeFilter("all");
                }}
                className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100"
              >
                Clear
              </button>
            </div>
          </div>
        </div>

        <div className="divide-y divide-slate-100">
          {pagedCustomers.map((customer) => (
            <button
              key={customer.id}
              type="button"
              onClick={() => setSelectedCustomerId(customer.id)}
              aria-pressed={selectedCustomer?.id === customer.id}
              className={`grid w-full gap-3 border-l-4 px-5 py-4 text-left transition hover:bg-slate-50 lg:grid-cols-[1fr_140px_130px_150px] lg:items-center ${
                selectedCustomer?.id === customer.id
                  ? "border-l-sky-500 bg-sky-50"
                  : "border-l-transparent bg-white"
              }`}
            >
              <div>
                <p className="font-semibold text-slate-950">
                  {customer.display_name}
                </p>
                <p className="mt-1 text-sm text-slate-500">
                  {customer.property_address}
                </p>
                <p className="mt-1 text-xs font-semibold uppercase text-slate-400">
                  {customer.contact_name}
                  {customer.phone ? ` - ${customer.phone}` : ""}
                  {customer.email ? ` - ${customer.email}` : ""}
                </p>
              </div>
              <Badge
                label={customerStatusLabel(customer.status)}
                tone={customer.status === "inactive" ? "amber" : "green"}
              />
              <span className="text-sm font-semibold text-slate-600">
                {customerTypeLabel(customer.customer_type)}
              </span>
              <span className="text-sm text-slate-600">
                {companyMap.get(customer.company_id)?.name ?? "Company"}
              </span>
            </button>
          ))}

          {!filteredCustomers.length ? (
            <EmptyState label="No customers match this view." />
          ) : null}
        </div>
        <PaginationControls
          page={customerPage}
          pageCount={customerPageCount}
          total={filteredCustomers.length}
          onPageChange={setCustomerPage}
        />
      </section>

      <aside className="space-y-5">
        <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm">
          <h3 className="text-lg font-bold text-slate-950">New customer</h3>
          <CustomerCreateForm
            companies={snapshot.companies}
            isSubmitting={isCreatingCustomer}
            onSubmit={handleCreateCustomer}
          />
        </section>

        {selectedCustomer ? (
          <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm">
            <h3 className="text-lg font-bold text-slate-950">
              {selectedCustomer.display_name}
            </h3>
            <p className="mt-1 text-sm text-slate-500">
              {selectedCustomer.contact_name}
            </p>
            <div className="mt-4 grid gap-2 text-sm text-slate-600">
              <ContactLine icon={Phone} value={selectedCustomer.phone} />
              <ContactLine icon={Mail} value={selectedCustomer.email} />
              <ContactLine icon={Building2} value={selectedCustomer.property_address} />
            </div>

            <CustomerProfilePanel
              snapshot={snapshot}
              companyMap={companyMap}
              customer={selectedCustomer}
              onViewChange={onViewChange}
              onAddNote={handleFocusCustomerNotes}
            />

            <form
              key={selectedCustomer.id}
              onSubmit={handleUpdateCustomer}
              className="mt-5 grid gap-3 rounded-lg border border-slate-200 bg-slate-50 p-4"
            >
              <div>
                <p className="text-sm font-bold text-slate-950">Edit customer profile</p>
                <p className="mt-1 text-sm text-slate-500">
                  Keep contact, property, notes, and account status current.
                </p>
              </div>
              <label className="grid gap-1 text-sm font-medium text-slate-700">
                Company
                <select
                  name="company_id"
                  defaultValue={selectedCustomer.company_id}
                  className="rounded-md border border-slate-300 px-3 py-2"
                >
                  {snapshot.companies.map((company) => (
                    <option key={company.id} value={company.id}>
                      {company.name}
                    </option>
                  ))}
                </select>
              </label>
              <div className="grid gap-3 sm:grid-cols-2">
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Display name
                  <input
                    name="display_name"
                    required
                    defaultValue={selectedCustomer.display_name}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Primary contact
                  <input
                    name="contact_name"
                    required
                    defaultValue={selectedCustomer.contact_name}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
              </div>
              <div className="grid gap-3 sm:grid-cols-2">
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Phone
                  <input
                    name="phone"
                    defaultValue={selectedCustomer.phone ?? ""}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Email
                  <input
                    name="email"
                    type="email"
                    defaultValue={selectedCustomer.email ?? ""}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
              </div>
              <label className="grid gap-1 text-sm font-medium text-slate-700">
                Property address
                <input
                  name="property_address"
                  required
                  defaultValue={selectedCustomer.property_address}
                  className="rounded-md border border-slate-300 px-3 py-2"
                />
              </label>
              <div className="grid gap-3 sm:grid-cols-3">
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  City
                  <input
                    name="city"
                    defaultValue={selectedCustomer.city ?? ""}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  State
                  <input
                    name="state"
                    defaultValue={selectedCustomer.state}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  ZIP
                  <input
                    name="postal_code"
                    defaultValue={selectedCustomer.postal_code ?? ""}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  />
                </label>
              </div>
              <div className="grid gap-3 sm:grid-cols-2">
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Status
                  <select
                    name="status"
                    defaultValue={selectedCustomer.status}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  >
                    {customerStatuses.map((status) => (
                      <option key={status.value} value={status.value}>
                        {status.label}
                      </option>
                    ))}
                  </select>
                </label>
                <label className="grid gap-1 text-sm font-medium text-slate-700">
                  Type
                  <select
                    name="customer_type"
                    defaultValue={selectedCustomer.customer_type}
                    className="rounded-md border border-slate-300 px-3 py-2"
                  >
                    {customerTypes.map((type) => (
                      <option key={type.value} value={type.value}>
                        {type.label}
                      </option>
                    ))}
                  </select>
                </label>
              </div>
              <label className="grid gap-1 text-sm font-medium text-slate-700">
                Notes
                <textarea
                  ref={customerNotesRef}
                  name="notes"
                  defaultValue={selectedCustomer.notes ?? ""}
                  className="min-h-24 rounded-md border border-slate-300 px-3 py-2"
                />
              </label>
              <button
                type="submit"
                disabled={isUpdatingCustomer}
                className="rounded-md bg-slate-950 px-4 py-2 text-sm font-semibold text-white hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-300"
              >
                {isUpdatingCustomer ? "Saving customer" : "Save customer"}
              </button>
            </form>
          </section>
        ) : null}
      </aside>
    </div>
  );
}

function CustomerProfilePanel({
  snapshot,
  companyMap,
  customer,
  onViewChange,
  onAddNote,
}: {
  snapshot: CrmSnapshot;
  companyMap: Map<string, CompanyRecord>;
  customer: CustomerRecord;
  onViewChange: (view: WorkspaceView) => void;
  onAddNote: () => void;
}) {
  const [activeSection, setActiveSection] =
    useState<CustomerWorkspaceSection>("overview");
  const [timelineFilter, setTimelineFilter] = useState<CustomerTimelineKind | "all">(
    "all",
  );
  const related = useMemo(
    () => getCustomerRelatedRecords(snapshot, customer),
    [customer, snapshot],
  );
  const properties = useMemo(
    () => buildCustomerPropertySummaries(customer, related),
    [customer, related],
  );
  const communicationItems = useMemo(
    () => getCustomerCommunicationItems(snapshot, companyMap, customer, related),
    [companyMap, customer, related, snapshot],
  );
  const timelineItems = useMemo(
    () => buildCustomerTimelineItems(customer, related, communicationItems),
    [communicationItems, customer, related],
  );
  const duplicateMatches = useMemo(
    () =>
      findPotentialCustomerDuplicates(
        snapshot.customers,
        {
          company_id: customer.company_id,
          display_name: customer.display_name,
          contact_name: customer.contact_name,
          phone: customer.phone,
          email: customer.email,
          property_address: customer.property_address,
          city: customer.city,
          state: customer.state,
          postal_code: customer.postal_code,
          customer_type: customer.customer_type,
          status: customer.status,
          notes: customer.notes,
        },
        customer.id,
      ),
    [customer, snapshot.customers],
  );
  const company = companyMap.get(customer.company_id);
  const openEstimates = related.estimates.filter(isOpenEstimate);
  const activeJobs = related.jobs.filter(isActiveJob);
  const outstandingInvoices = related.invoices.filter(isOutstandingInvoice);
  const realTimelineItems = timelineItems.filter((item) => item.kind !== "future");
  const lastActivity = realTimelineItems[0];
  const leadSources = uniqueById(
    related.leads.map((lead) => ({ id: lead.source, label: lead.source })),
  )
    .map((lead) => lead.label)
    .filter(Boolean);
  const outstandingInvoiceTotal = outstandingInvoices.reduce(
    (total, invoice) => total + invoice.balance_due,
    0,
  );
  const lifetimeRevenue = getCustomerLifetimeRevenue(related);
  const warrantyStatus = getCustomerWarrantyStatus(related);
  const nextAppointment = getCustomerNextAppointment(related);
  const lastCommunication = getCustomerLastCommunication(communicationItems);
  const primaryPhoto = getCustomerPrimaryPhoto(related);
  const sectionCounts: Record<CustomerWorkspaceSection, number | null> = {
    overview: null,
    properties: properties.length,
    activity: realTimelineItems.length,
    leads: related.leads.length,
    estimates: related.estimates.length,
    inspections: related.inspections.length,
    jobs: related.jobs.length,
    invoices: related.invoices.length,
    photos: related.photos.length,
    documents: related.documents.length,
    notes: customer.notes ? 1 : 0,
    calendar: related.scheduleEvents.length,
    warranty: 0,
    maintenance: 0,
    communications: communicationItems.length,
  };

  return (
    <div
      className="mt-5 border-t border-slate-200 pt-5"
      data-testid="customer-workspace"
    >
      <div
        className="rounded-xl border border-slate-200 bg-gradient-to-br from-white via-white to-slate-50 p-4 shadow-sm"
        data-testid="customer-360-header"
      >
        <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_260px] xl:items-stretch">
          <div className="flex min-w-0 flex-col gap-4 sm:flex-row">
            <div
              className="grid h-20 w-20 shrink-0 place-items-center rounded-xl text-xl font-black text-white shadow-sm"
              style={{ backgroundColor: getCompanyBrandColor(company) }}
              aria-label={`${customer.display_name} customer logo`}
            >
              {getCustomerInitials(customer) || companyInitials(company)}
            </div>
            <div className="min-w-0 flex-1">
              <p className="text-xs font-bold uppercase text-slate-500">
                Customer 360 workspace
              </p>
              <h4 className="mt-1 text-2xl font-black tracking-tight text-slate-950">
                {customer.display_name}
              </h4>
              <p className="mt-1 text-sm text-slate-600">
                {company?.name ?? "Company"} - {customer.contact_name}
              </p>
              <div className="mt-3 flex flex-wrap gap-2" aria-label="Customer status badges">
                <Badge
                  label={customerStatusLabel(customer.status)}
                  tone={customer.status === "inactive" ? "amber" : "green"}
                />
                <Badge label={customerTypeLabel(customer.customer_type)} tone="blue" />
                <Badge
                  label={leadSources.length ? leadSources[0] : "No linked source"}
                  tone="amber"
                />
                <Badge label={warrantyStatus.label} tone={warrantyStatus.tone} />
              </div>
              <div className="mt-4 grid gap-2 text-sm text-slate-600 md:grid-cols-2">
                <ContactLine icon={Phone} value={customer.phone} />
                <ContactLine icon={Mail} value={customer.email} />
                <ContactLine
                  icon={MapPin}
                  value={
                    properties[0]
                      ? formatCustomerPropertyAddress(properties[0])
                      : customer.property_address
                  }
                />
                <ContactLine
                  icon={CalendarClock}
                  value={
                    nextAppointment
                      ? formatDateTime(nextAppointment.start_at)
                      : "No upcoming appointment"
                  }
                />
              </div>
            </div>
          </div>
          <div className="overflow-hidden rounded-xl border border-slate-200 bg-slate-100">
            {primaryPhoto ? (
              <Image
                src={primaryPhoto.file_url}
                alt={primaryPhoto.caption ?? primaryPhoto.label ?? "Customer property photo"}
                width={640}
                height={176}
                unoptimized
                className="h-44 w-full object-cover"
              />
            ) : (
              <div className="grid h-44 place-items-center bg-slate-100 text-slate-500">
                <div className="text-center">
                  <Camera className="mx-auto h-8 w-8" />
                  <p className="mt-2 text-sm font-semibold">Property photo</p>
                  <p className="text-xs">No linked photo yet</p>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-8">
          <ProfileStat label="Properties" value={properties.length} />
          <ProfileStat label="Active jobs" value={activeJobs.length} />
          <ProfileStat label="Open estimates" value={openEstimates.length} />
          <ProfileStat
            label="Outstanding invoices"
            value={formatMoney(outstandingInvoiceTotal)}
          />
          <ProfileStat label="Lifetime revenue" value={formatMoney(lifetimeRevenue)} />
          <ProfileStat label="Customer since" value={formatDate(customer.created_at)} />
          <ProfileStat
            label="Warranty"
            value={warrantyStatus.label}
          />
          <ProfileStat
            label="Last communication"
            value={
              lastCommunication
                ? formatDateTime(lastCommunication.createdAt)
                : "No contact"
            }
          />
        </div>

        <div className="mt-3 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-600">
          Last activity:{" "}
          <span className="font-semibold text-slate-900">
            {lastActivity
              ? `${lastActivity.label} - ${formatDateTime(lastActivity.occurredAt)}`
              : "No activity yet"}
          </span>
          <span className="mx-2 text-slate-300">|</span>
          <span className="font-semibold text-slate-900">{warrantyStatus.detail}</span>
        </div>
      </div>

      <div
        className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-4"
        data-testid="customer-quick-actions"
      >
        <CustomerQuickAction
          label="Create Estimate"
          detail="Build pricing from this customer context."
          icon={Calculator}
          onClick={() => onViewChange("estimates")}
        />
        <CustomerQuickAction
          label="Schedule Inspection"
          detail="Open the inspection workflow for this property."
          icon={ClipboardList}
          onClick={() => onViewChange("inspections")}
        />
        <CustomerQuickAction
          label="Schedule Job"
          detail="Move approved work into production."
          icon={Building2}
          onClick={() => onViewChange("jobs")}
        />
        <CustomerQuickAction
          label="Open Communications"
          detail="Review website, Yelp, SMS, and email activity."
          icon={MessageSquare}
          onClick={() => setActiveSection("communications")}
        />
        <CustomerQuickAction
          label="Add Internal Note"
          detail="Jump to the customer note field."
          icon={Pencil}
          onClick={onAddNote}
        />
        <CustomerQuickAction
          label="Upload Photos"
          detail="Attach jobsite or property photos."
          icon={Camera}
          onClick={() => onViewChange("photos")}
        />
        <CustomerQuickAction
          label="Create Invoice"
          detail="Prepare billing for linked work."
          icon={ReceiptText}
          onClick={() => onViewChange("invoices")}
        />
        <CustomerQuickAction
          label="Open Calendar"
          detail="View scheduled visits and production dates."
          icon={CalendarClock}
          onClick={() => onViewChange("calendar")}
        />
      </div>

      {duplicateMatches.length ? (
        <div className="mt-4 rounded-lg border border-amber-200 bg-amber-50 p-3">
          <p className="text-sm font-bold text-amber-900">Potential duplicate review</p>
          <p className="mt-1 text-sm text-amber-800">
            Merge is not automated. Review these matches before creating or editing
            records so customer and property history stays clean.
          </p>
          <div className="mt-2 grid gap-2">
            {duplicateMatches.slice(0, 3).map((match) => (
              <p key={match.customer.id} className="text-sm text-amber-800">
                {match.customer.display_name} has {match.reasons.join(" and ")}.
              </p>
            ))}
          </div>
        </div>
      ) : null}

      <div className="mt-4 flex gap-2 overflow-x-auto pb-1">
        {customerWorkspaceSections.map((section) => (
          <button
            key={section.value}
            type="button"
            onClick={() => setActiveSection(section.value)}
            aria-pressed={activeSection === section.value}
            className={`inline-flex shrink-0 items-center gap-2 rounded-md border px-3 py-2 text-sm font-semibold transition ${
              activeSection === section.value
                ? "border-sky-400 bg-sky-50 text-sky-800"
                : "border-slate-200 bg-white text-slate-600 hover:bg-slate-50"
            }`}
          >
            {section.label}
            {sectionCounts[section.value] !== null ? (
              <span className="rounded-full bg-slate-100 px-1.5 py-0.5 text-xs text-slate-500">
                {sectionCounts[section.value]}
              </span>
            ) : null}
          </button>
        ))}
      </div>

      <div className="mt-4" data-testid="customer-workspace-section">
        {activeSection === "overview" ? (
          <CustomerOverviewSection
            customer={customer}
            company={company}
            related={related}
            properties={properties}
            leadSources={leadSources}
            communicationsCount={communicationItems.length}
          />
        ) : null}

        {activeSection === "properties" ? (
          <CustomerPropertiesSection properties={properties} />
        ) : null}

        {activeSection === "activity" ? (
          <CustomerTimeline
            items={timelineItems}
            filter={timelineFilter}
            onFilterChange={setTimelineFilter}
          />
        ) : null}

        {activeSection === "leads" ? (
          <RelatedList
            title="Leads"
            emptyLabel="No leads linked yet."
            items={related.leads.map((lead) => ({
              id: lead.id,
              title: lead.contact_name,
              meta: `${pipelineStageLabel(lead.pipeline_stage)} - ${formatMoney(
                lead.estimated_value,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "estimates" ? (
          <RelatedList
            title="Estimates"
            emptyLabel="No estimates linked yet."
            items={related.estimates.map((estimate) => ({
              id: estimate.id,
              title: estimate.title,
              meta: `${estimateStatusLabel(estimate.status)} - ${formatMoney(
                estimate.total,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "inspections" ? (
          <RelatedList
            title="Inspections"
            emptyLabel="No inspections linked yet."
            items={related.inspections.map((inspection) => ({
              id: inspection.id,
              title: inspection.title,
              meta: `${inspectionStatusLabel(inspection.status)} - ${formatDateTime(
                inspection.updated_at,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "jobs" ? (
          <RelatedList
            title="Jobs"
            emptyLabel="No jobs linked yet."
            items={related.jobs.map((job) => ({
              id: job.id,
              title: job.title,
              meta: `${jobStatusLabel(job.status)} - ${formatDate(
                job.start_date ?? job.scheduled_start,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "invoices" ? (
          <RelatedList
            title="Invoices"
            emptyLabel="No invoices linked yet."
            items={related.invoices.map((invoice) => ({
              id: invoice.id,
              title: invoice.invoice_number,
              meta: `${invoiceStatusLabel(invoice.status)} - ${formatMoney(
                invoice.balance_due,
              )} due`,
            }))}
          />
        ) : null}

        {activeSection === "photos" ? (
          <RelatedList
            title="Photos"
            emptyLabel="No photos linked yet."
            items={related.photos.map((photo) => ({
              id: photo.id,
              title: photo.caption ?? photo.label ?? "Job photo",
              meta: `${photo.is_customer_visible ? "Customer visible" : "Internal"} - ${formatDate(
                photo.taken_at ?? photo.created_at,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "documents" ? (
          <RelatedList
            title="Documents"
            emptyLabel="No documents linked yet."
            items={related.documents.map((document) => ({
              id: document.id,
              title: document.title,
              meta: `${documentCategoryLabel(document.category)} - ${documentStatusLabel(
                document.status,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "notes" ? (
          <RelatedList
            title="Notes"
            emptyLabel="No customer notes yet."
            items={
              customer.notes
                ? [
                    {
                      id: `note-${customer.id}`,
                      title: "Customer notes",
                      meta: truncateTimelineText(customer.notes, 180),
                    },
                  ]
                : []
            }
          />
        ) : null}

        {activeSection === "calendar" ? (
          <RelatedList
            title="Calendar"
            emptyLabel="No scheduled work linked yet."
            items={related.scheduleEvents.map((event) => ({
              id: event.id,
              title: event.title,
              meta: `${scheduleEventStatusLabel(event.status)} - ${formatDateTime(
                event.start_at,
              )}`,
            }))}
          />
        ) : null}

        {activeSection === "warranty" ? (
          <CustomerFutureSection
            title="Warranty"
            label="Warranty tracking is ready for a future schema-backed record."
            detail="Completed jobs, documents, and customer-visible photos are already linked here so warranty records can be added without changing this workspace."
          />
        ) : null}

        {activeSection === "maintenance" ? (
          <CustomerFutureSection
            title="Maintenance"
            label="Maintenance plans are prepared as a Customer 360 section."
            detail="Recurring roof reviews, paint touch-ups, and seasonal reminders need a dedicated maintenance table before they can be persisted."
          />
        ) : null}

        {activeSection === "communications" ? (
          <CustomerCommunicationsSection
            items={communicationItems}
            onOpenHub={() => onViewChange("inbox")}
          />
        ) : null}
      </div>
    </div>
  );
}

function CustomerQuickAction({
  label,
  detail,
  icon: Icon,
  onClick,
}: {
  label: string;
  detail: string;
  icon: typeof Home;
  onClick: () => void;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="group flex min-h-24 w-full items-start gap-3 rounded-lg border border-slate-200 bg-white p-3 text-left transition hover:-translate-y-0.5 hover:border-sky-300 hover:bg-sky-50 hover:shadow-sm focus:outline-none focus-visible:ring-2 focus-visible:ring-sky-300"
    >
      <span className="grid h-10 w-10 shrink-0 place-items-center rounded-md bg-sky-50 text-sky-700 transition group-hover:bg-white">
        <Icon className="h-5 w-5" />
      </span>
      <span className="min-w-0">
        <span className="block text-sm font-bold text-slate-950">{label}</span>
        <span className="mt-1 block text-xs leading-5 text-slate-500">{detail}</span>
      </span>
    </button>
  );
}

function CustomerOverviewSection({
  customer,
  company,
  related,
  properties,
  leadSources,
  communicationsCount,
}: {
  customer: CustomerRecord;
  company?: CompanyRecord;
  related: CustomerRelatedRecords;
  properties: CustomerPropertySummary[];
  leadSources: string[];
  communicationsCount: number;
}) {
  const openEstimateTotal = related.estimates
    .filter(isOpenEstimate)
    .reduce((total, estimate) => total + estimate.total, 0);
  const outstandingInvoiceTotal = related.invoices
    .filter(isOutstandingInvoice)
    .reduce((total, invoice) => total + invoice.balance_due, 0);
  const completedInspectionCount = related.inspections.filter(
    (inspection) => inspection.status === "completed" || inspection.completed_at,
  ).length;

  return (
    <div className="grid gap-3">
      <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">
        <CustomerSummaryCard
          title="Estimates"
          value={related.estimates.length}
          detail={`${formatMoney(openEstimateTotal)} open`}
          icon={Calculator}
          tone="blue"
        />
        <CustomerSummaryCard
          title="Jobs"
          value={related.jobs.length}
          detail={`${related.jobs.filter(isActiveJob).length} active`}
          icon={Building2}
          tone="purple"
        />
        <CustomerSummaryCard
          title="Inspections"
          value={related.inspections.length}
          detail={`${completedInspectionCount} completed`}
          icon={ClipboardList}
          tone="green"
        />
        <CustomerSummaryCard
          title="Financial"
          value={formatMoney(getCustomerLifetimeRevenue(related))}
          detail={`${formatMoney(outstandingInvoiceTotal)} outstanding`}
          icon={DollarSign}
          tone="amber"
        />
      </div>
      <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
        <p className="text-sm font-bold text-slate-950">Overview</p>
        <div className="mt-3 grid gap-2 text-sm sm:grid-cols-2">
          <CustomerDetail label="Customer" value={customer.display_name} />
          <CustomerDetail label="Primary contact" value={customer.contact_name} />
          <CustomerDetail label="Company" value={company?.name ?? "Company"} />
          <CustomerDetail label="Status" value={customerStatusLabel(customer.status)} />
          <CustomerDetail label="Primary phone" value={customer.phone ?? "No phone"} />
          <CustomerDetail label="Primary email" value={customer.email ?? "No email"} />
          <CustomerDetail
            label="Service address"
            value={[
              customer.property_address,
              customer.city,
              customer.state,
              customer.postal_code,
            ]
              .filter(Boolean)
              .join(", ")}
          />
          <CustomerDetail
            label="Lead source"
            value={leadSources.length ? leadSources.join(", ") : "No linked source"}
          />
          <CustomerDetail
            label="Property count"
            value={`${properties.length} ${
              properties.length === 1 ? "property" : "properties"
            }`}
          />
          <CustomerDetail
            label="Primary property"
            value={
              properties[0]
                ? formatCustomerPropertyAddress(properties[0])
                : "No property recorded"
            }
          />
        </div>
      </div>
      <div className="grid gap-3 sm:grid-cols-3">
        <CustomerSummaryCard
          title="Documents"
          value={related.documents.length}
          detail={`${related.documents.filter((document) => document.status === "draft").length} drafts`}
          icon={FileText}
          tone="slate"
        />
        <CustomerSummaryCard
          title="Communications"
          value={communicationsCount}
          detail="Linked inbox activity"
          icon={MessageSquare}
          tone="blue"
        />
        <CustomerSummaryCard
          title="Photos"
          value={related.photos.length}
          detail={`${related.photos.filter((photo) => photo.is_customer_visible).length} customer-visible`}
          icon={Camera}
          tone="green"
        />
      </div>
    </div>
  );
}

function CustomerSummaryCard({
  title,
  value,
  detail,
  icon: Icon,
  tone,
}: {
  title: string;
  value: string | number;
  detail: string;
  icon: typeof Home;
  tone: "blue" | "green" | "amber" | "purple" | "slate";
}) {
  const toneClass =
    tone === "green"
      ? "bg-emerald-50 text-emerald-700"
      : tone === "amber"
        ? "bg-amber-50 text-amber-700"
        : tone === "purple"
          ? "bg-purple-50 text-purple-700"
          : tone === "blue"
            ? "bg-sky-50 text-sky-700"
            : "bg-slate-100 text-slate-600";

  return (
    <div className="rounded-lg border border-slate-200 bg-white p-3 shadow-sm">
      <div className="flex items-start justify-between gap-3">
        <div>
          <p className="text-xs font-semibold uppercase text-slate-500">{title}</p>
          <p className="mt-1 text-xl font-black tracking-tight text-slate-950">
            {value}
          </p>
        </div>
        <span className={`grid h-10 w-10 shrink-0 place-items-center rounded-md ${toneClass}`}>
          <Icon className="h-5 w-5" />
        </span>
      </div>
      <p className="mt-3 text-sm text-slate-500">{detail}</p>
    </div>
  );
}

function CustomerPropertiesSection({
  properties,
}: {
  properties: CustomerPropertySummary[];
}) {
  if (!properties.length) {
    return <EmptyState label="No properties are linked to this customer yet." />;
  }

  return (
    <div className="grid gap-3" data-testid="customer-properties-section">
      {properties.map((property, index) => (
        <div
          key={property.id}
          className="overflow-hidden rounded-xl border border-slate-200 bg-white shadow-sm"
        >
          <div className="grid gap-0 lg:grid-cols-[180px_minmax(0,1fr)]">
            <div className="bg-slate-100">
              {property.photos[0] ? (
                <Image
                  src={property.photos[0].file_url}
                  alt={property.photos[0].caption ?? property.photos[0].label ?? "Property photo"}
                  width={360}
                  height={176}
                  unoptimized
                  className="h-44 w-full object-cover lg:h-full"
                />
              ) : (
                <div className="grid h-44 place-items-center text-slate-500 lg:h-full">
                  <div className="text-center">
                    <Home className="mx-auto h-7 w-7" />
                    <p className="mt-2 text-xs font-semibold uppercase">Property</p>
                  </div>
                </div>
              )}
            </div>
            <div className="p-4">
              <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
                <div>
                  <p className="text-sm font-bold text-slate-950">
                    {index === 0 ? "Primary service property" : "Linked property"}
                  </p>
                  <p className="mt-1 text-sm text-slate-600">
                    {formatCustomerPropertyAddress(property)}
                  </p>
                </div>
                <Badge
                  label={
                    property.activeWorkCount
                      ? `${property.activeWorkCount} active`
                      : "No active work"
                  }
                  tone={property.activeWorkCount ? "blue" : "green"}
                />
              </div>

              <div className="mt-4 grid gap-3 md:grid-cols-2 xl:grid-cols-3">
                <CustomerDetail label="Roof system" value={property.roofSystem} />
                <CustomerDetail label="Roof age" value={property.roofAge} />
                <CustomerDetail label="Exterior paint colors" value={property.exteriorPaintColors} />
                <CustomerDetail label="HOA" value={property.hoa} />
                <CustomerDetail label="Gate codes" value={property.gateCodes} />
                <CustomerDetail label="Access instructions" value={property.accessInstructions} />
                <CustomerDetail label="Pets" value={property.pets} />
                <CustomerDetail label="Solar" value={property.solar} />
                <CustomerDetail label="HVAC notes" value={property.hvacNotes} />
              </div>

              <div className="mt-4 grid gap-3 sm:grid-cols-3">
                <ProfileStat label="Warranty docs" value={property.warrantyDocuments.length} />
                <ProfileStat label="Photos" value={property.photos.length} />
                <ProfileStat label="Inspection history" value={property.inspections.length} />
              </div>

              <div className="mt-3 flex flex-wrap gap-2">
                {property.sources.map((source) => (
                  <span
                    key={source}
                    className="rounded-md bg-slate-100 px-2 py-1 text-xs font-semibold text-slate-600"
                  >
                    {source}
                  </span>
                ))}
              </div>
              <p className="mt-3 text-xs font-semibold uppercase text-slate-400">
                Last linked activity {formatDateTime(property.lastActivity)}
              </p>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

function CustomerCommunicationsSection({
  items,
  onOpenHub,
}: {
  items: UnifiedInboxItem[];
  onOpenHub: () => void;
}) {
  const latestItem = items[0];
  const latestSms = items.find((item) => item.channel === "sms");
  const latestCall = items.find((item) => item.channel === "phone_call");
  const missedCallCount = items.filter((item) => item.isMissedCall).length;
  const failedCount = items.filter((item) => item.isFailed).length;
  const unreadCount = items.filter((item) => item.isUnread).length;
  const followUpCount = items.filter(communicationItemIsFollowUpDue).length;

  return (
    <div className="grid gap-3" data-testid="customer-communications-section">
      <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <p className="text-sm font-bold text-slate-950">Communications</p>
            <p className="mt-1 text-sm text-slate-500">
              Customer-linked leads, SMS, email drafts, calendar events, internal
              notes, and integration activity. Internal records stay staff-facing.
            </p>
          </div>
          <button
            type="button"
            onClick={onOpenHub}
            className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100"
          >
            Open Hub
          </button>
        </div>

        <div className="mt-4 grid gap-2 sm:grid-cols-4">
          <ProfileStat label="Linked" value={items.length} />
          <ProfileStat label="Unread/new" value={unreadCount} />
          <ProfileStat label="Failed" value={failedCount} />
          <ProfileStat label="Follow-ups" value={followUpCount} />
        </div>

        <div className="mt-3 grid gap-2 sm:grid-cols-4">
          <ProfileStat
            label="Latest SMS"
            value={latestSms ? formatDateTime(latestSms.createdAt) : "None"}
          />
          <ProfileStat
            label="Latest call"
            value={latestCall ? formatDateTime(latestCall.createdAt) : "None"}
          />
          <ProfileStat label="Missed calls" value={missedCallCount} />
          <ProfileStat label="Unread messages" value={unreadCount} />
        </div>

        <div className="mt-3 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-600">
          Most recent contact:{" "}
          <span className="font-semibold text-slate-900">
            {latestItem
              ? `${communicationChannelLabels[latestItem.channel]} - ${formatDateTime(
                  latestItem.createdAt,
                )}`
              : "No linked communications yet"}
          </span>
        </div>

        <div className="mt-3 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-sm text-amber-900">
          Live Twilio SMS/call routing is setup-required. Existing linked
          communications remain factual; future missed calls and unread messages
          will appear only after verified Twilio webhooks are enabled.
        </div>
      </div>

      {items.length ? (
        <div className="divide-y divide-slate-100 rounded-lg border border-slate-200 bg-white">
          {items.slice(0, 8).map((item) => (
            <div key={item.id} className="grid gap-3 p-3 md:grid-cols-[1fr_auto]">
              <div className="min-w-0">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge
                    label={communicationChannelLabels[item.channel]}
                    tone={getCommunicationChannelTone(item.channel)}
                  />
                  <Badge
                    label={item.sourceLabel}
                    tone={getInboxProviderTone(item.provider)}
                  />
                  <Badge
                    label={getCommunicationDirectionLabel(item.direction)}
                    tone="blue"
                  />
                  <Badge label={item.status} tone={getCommunicationStatusTone(item)} />
                </div>
                <p className="mt-2 font-semibold text-slate-950">{item.customerName}</p>
                <p className="mt-1 text-sm text-slate-500">{item.contact}</p>
                <p className="mt-2 line-clamp-2 text-sm text-slate-600">
                  {item.summary}
                </p>
              </div>
              <div className="text-sm text-slate-600 md:text-right">
                <p className="font-semibold text-slate-950">
                  {formatDateTime(item.createdAt)}
                </p>
                <p className="mt-1">{item.sourceAccount ?? item.businessLocation}</p>
                <p className="mt-2 text-xs font-semibold uppercase text-slate-400">
                  {item.assignedTo ?? "Unassigned"}
                </p>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <EmptyState label="No customer-linked communications yet." />
      )}
    </div>
  );
}

function CustomerDetail({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <p className="text-xs font-semibold uppercase text-slate-500">{label}</p>
      <p className="mt-0.5 font-medium text-slate-800">{value}</p>
    </div>
  );
}

function CustomerTimeline({
  items,
  filter,
  onFilterChange,
}: {
  items: CustomerTimelineItem[];
  filter: CustomerTimelineKind | "all";
  onFilterChange: (filter: CustomerTimelineKind | "all") => void;
}) {
  const filteredItems =
    filter === "all" ? items : items.filter((item) => item.kind === filter);

  if (!items.length) {
    return <EmptyState label="No customer activity yet." />;
  }

  return (
    <div data-testid="customer-timeline">
      <div className="mb-3 flex flex-col gap-2 rounded-lg border border-slate-200 bg-slate-50 p-3 sm:flex-row sm:items-center sm:justify-between">
        <p className="text-sm font-bold text-slate-900">Activity timeline</p>
        <label className="flex items-center gap-2 text-sm font-semibold text-slate-600">
          Filter
          <select
            value={filter}
            onChange={(event) =>
              onFilterChange(event.target.value as CustomerTimelineKind | "all")
            }
            data-testid="customer-timeline-filter"
            className="rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-medium text-slate-700"
          >
            {customerTimelineFilters.map((item) => (
              <option key={item.value} value={item.value}>
                {item.label}
              </option>
            ))}
          </select>
        </label>
      </div>

      {filteredItems.length ? (
        <div className="divide-y divide-slate-100 rounded-lg border border-slate-200">
          {filteredItems.slice(0, 16).map((item) => {
            const Icon = item.icon;
            const toneClass =
              item.tone === "green"
                ? "bg-emerald-50 text-emerald-700"
                : item.tone === "amber"
                  ? "bg-amber-50 text-amber-700"
                  : item.tone === "purple"
                    ? "bg-purple-50 text-purple-700"
                    : item.tone === "blue"
                      ? "bg-sky-50 text-sky-700"
                      : "bg-slate-100 text-slate-600";

            return (
              <div key={item.id} className="flex gap-3 p-3">
                <div
                  className={`flex h-9 w-9 shrink-0 items-center justify-center rounded-full ${toneClass}`}
                >
                  <Icon className="h-4 w-4" />
                </div>
                <div className="min-w-0 flex-1">
                  <div className="flex flex-col gap-1 sm:flex-row sm:items-center sm:justify-between">
                    <p className="font-semibold text-slate-950">{item.label}</p>
                    <p className="text-xs font-medium text-slate-500">
                      {formatDateTime(item.occurredAt)}
                    </p>
                  </div>
                  <p className="mt-1 text-sm text-slate-600">{item.description}</p>
                  <p className="mt-1 text-xs font-semibold uppercase text-slate-400">
                    {item.user}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <EmptyState label="No activity matches this filter." />
      )}
    </div>
  );
}

function CustomerFutureSection({
  title,
  label,
  detail,
}: {
  title: string;
  label: string;
  detail: string;
}) {
  return (
    <div className="rounded-lg border border-dashed border-slate-300 bg-slate-50 p-4">
      <div className="flex gap-3">
        <div className="grid h-10 w-10 shrink-0 place-items-center rounded-md bg-white text-slate-500">
          <ClockIcon />
        </div>
        <div>
          <p className="text-sm font-bold text-slate-950">{title}</p>
          <p className="mt-1 text-sm font-semibold text-slate-700">{label}</p>
          <p className="mt-1 text-sm text-slate-500">{detail}</p>
        </div>
      </div>
    </div>
  );
}

function ClockIcon() {
  return <CalendarClock className="h-5 w-5" />;
}

function ProfileStat({ label, value }: { label: string; value: string | number }) {
  return (
    <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
      <p className="text-xs font-semibold uppercase text-slate-500">{label}</p>
      <p className="mt-1 text-lg font-bold text-slate-950">{value}</p>
    </div>
  );
}

function RelatedList({
  title,
  emptyLabel,
  items,
}: {
  title: string;
  emptyLabel: string;
  items: { id: string; title: string; meta: string }[];
}) {
  return (
    <div className="rounded-lg border border-slate-200">
      <div className="border-b border-slate-200 px-3 py-2">
        <p className="text-sm font-bold text-slate-950">{title}</p>
      </div>
      {items.length ? (
        <div className="divide-y divide-slate-100">
          {items.slice(0, 4).map((item) => (
            <div key={item.id} className="px-3 py-2">
              <p className="text-sm font-semibold text-slate-800">{item.title}</p>
              <p className="mt-0.5 text-xs text-slate-500">{item.meta}</p>
            </div>
          ))}
        </div>
      ) : (
        <p className="px-3 py-3 text-sm text-slate-500">{emptyLabel}</p>
      )}
    </div>
  );
}

type CustomerCreateFormProps = {
  companies: CompanyRecord[];
  isSubmitting: boolean;
  onSubmit: (event: FormEvent<HTMLFormElement>) => void;
};

function CustomerCreateForm({
  companies,
  isSubmitting,
  onSubmit,
}: CustomerCreateFormProps) {
  return (
    <form onSubmit={onSubmit} className="mt-4 grid gap-3">
      <select
        name="company_id"
        required
        className="rounded-md border border-slate-300 px-3 py-2 text-sm"
      >
        {companies.map((company) => (
          <option key={company.id} value={company.id}>
            {company.name}
          </option>
        ))}
      </select>
      <input
        required
        name="display_name"
        className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Customer display name"
      />
      <input
        required
        name="contact_name"
        className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Primary contact"
      />
      <input
        required
        name="property_address"
        className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Property address"
      />
      <div className="grid gap-3 sm:grid-cols-2">
        <input
          name="phone"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          placeholder="Phone"
        />
        <input
          name="email"
          type="email"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          placeholder="Email"
        />
      </div>
      <div className="grid gap-3 sm:grid-cols-3">
        <input
          name="city"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          placeholder="City"
        />
        <input
          name="state"
          defaultValue="AZ"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          placeholder="State"
        />
        <input
          name="postal_code"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          placeholder="ZIP"
        />
      </div>
      <div className="grid gap-3 sm:grid-cols-2">
        <select
          name="customer_type"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        >
          {customerTypes.map((type) => (
            <option key={type.value} value={type.value}>
              {type.label}
            </option>
          ))}
        </select>
        <select
          name="status"
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        >
          {customerStatuses.map((status) => (
            <option key={status.value} value={status.value}>
              {status.label}
            </option>
          ))}
        </select>
      </div>
      <textarea
        name="notes"
        className="min-h-20 rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Notes"
      />
      <button
        type="submit"
        disabled={isSubmitting}
        className="inline-flex items-center justify-center gap-2 rounded-md bg-sky-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-sky-700 disabled:cursor-not-allowed disabled:bg-slate-300"
      >
        <Plus className="h-4 w-4" />
        {isSubmitting ? "Creating customer" : "Create customer"}
      </button>
    </form>
  );
}

type EstimatesViewProps = {
  client: CrmClient;
  snapshot: CrmSnapshot;
  companyMap: Map<string, CompanyRecord>;
  onReload: () => Promise<void>;
  onNotice: (message: string) => void;
  onError: (message: string) => void;
};

function EstimatesView({
  client,
  snapshot,
  companyMap,
  onReload,
  onNotice,
  onError,
}: EstimatesViewProps) {
  const [selectedEstimateId, setSelectedEstimateId] = useState(
    snapshot.estimates[0]?.id ?? "new",
  );
  const [estimateDraftVersion, setEstimateDraftVersion] = useState(0);
  const [search, setSearch] = useState("");
  const [statusFilter, setStatusFilter] = useState<EstimateStatus | "all">("all");

  const selectedEstimate =
    snapshot.estimates.find((estimate) => estimate.id === selectedEstimateId) ?? null;
  const selectedLineItems = selectedEstimate
    ? getEstimateLineItems(snapshot, selectedEstimate.id)
    : [];
  const filteredEstimates = snapshot.estimates.filter((estimate) => {
    const query = search.toLowerCase();
    const target = getEstimateTargetName(snapshot, estimate).toLowerCase();
    const matchesSearch =
      !query ||
      estimate.title.toLowerCase().includes(query) ||
      target.includes(query) ||
      (estimate.business ?? "").toLowerCase().includes(query) ||
      (estimate.location ?? "").toLowerCase().includes(query) ||
      (estimate.scope_of_work ?? "").toLowerCase().includes(query) ||
      estimateStatusLabel(estimate.status).toLowerCase().includes(query);
    const matchesStatus = statusFilter === "all" || estimate.status === statusFilter;
    return matchesSearch && matchesStatus;
  });
  const {
    page: estimatePage,
    pageCount: estimatePageCount,
    setPage: setEstimatePage,
    pagedItems: pagedEstimates,
  } = usePagination(filteredEstimates);
  const selectedEstimateJob = selectedEstimate
    ? snapshot.jobs.find((job) => job.estimate_id === selectedEstimate.id) ?? null
    : null;
  const selectedEstimateScope = selectedEstimate
    ? snapshot.scopes.find((scope) => scope.estimate_id === selectedEstimate.id) ?? null
    : null;
  const selectedEstimateDocuments = selectedEstimate
    ? snapshot.documents.filter((document) => document.estimate_id === selectedEstimate.id)
    : [];
  const selectedEstimateDocumentIds = new Set(
    selectedEstimateDocuments.map((document) => document.id),
  );
  const selectedEstimateSignatures = snapshot.signatures.filter(
    (signature) =>
      signature.document_id !== null && selectedEstimateDocumentIds.has(signature.document_id),
  );
  const isCreatingEstimate = selectedEstimateId === "new" || selectedEstimate === null;

  const handleStartNewEstimate = () => {
    updateUiPreservingScrollPosition(() => {
      setSelectedEstimateId("new");
      setEstimateDraftVersion((version) => version + 1);
    });
  };

  const handleSelectEstimate = (estimateId: string) => {
    updateUiPreservingScrollPosition(() => setSelectedEstimateId(estimateId));
  };

  const handleSaveEstimate = async (
    input: EstimateInput,
    lineItems: EstimateLineItemInput[],
  ) => {
    onError("");

    try {
      const savedEstimate = selectedEstimate
        ? await updateEstimate(client, selectedEstimate.id, input, lineItems)
        : await createEstimate(client, input, lineItems);

      updateUiPreservingScrollPosition(() =>
        setSelectedEstimateId(savedEstimate.id),
      );
      await onReload();
      onNotice(
        selectedEstimate
          ? "Estimate updated."
          : "Draft estimate saved.",
      );
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to save estimate."));
    }
  };

  const handleCreateJobFromEstimate = async (estimate: EstimateRecord) => {
    if (selectedEstimateJob) {
      onNotice("This estimate already has a linked job.");
      return;
    }

    try {
      const job = await createJob(
        client,
        buildJobInputFromEstimate(
          snapshot,
          estimate,
          selectedEstimateScope?.id ?? null,
        ),
      );
      await onReload();
      onNotice(`Job created: ${job.title}`);
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to create job from estimate."));
    }
  };

  const handleSaveEstimateDocument = async (estimate: EstimateRecord) => {
    const documentDraft = buildGeneratedDocumentDraft(snapshot, `estimate:${estimate.id}`);

    if (!documentDraft) {
      onError("Unable to generate an estimate packet for this record.");
      return;
    }

    try {
      await createDocument(client, documentDraft);
      await onReload();
      onNotice("Estimate packet saved to documents.");
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to save estimate packet."));
    }
  };

  const handleGenerateScopeFromEstimate = async (estimate: EstimateRecord) => {
    if (selectedEstimateScope) {
      onNotice("This estimate already has a linked scope of work.");
      return;
    }

    const template = selectScopeTemplateForEstimate(snapshot, estimate);
    const lineItems = getEstimateLineItems(snapshot, estimate.id);
    const category = template?.category ?? getEstimateScopeCategory(estimate);
    const company = companyMap.get(estimate.company_id);
    const scopeBody = buildScopeBodyFromEstimate(snapshot, estimate, lineItems, template);

    try {
      const savedScope = await createScope(client, {
        company_id: estimate.company_id,
        customer_id: estimate.customer_id,
        lead_id: estimate.lead_id,
        estimate_id: estimate.id,
        template_id: template?.id ?? null,
        title: `${estimate.title} Scope of Work`,
        category,
        status: "ready",
        scope_body: scopeBody,
        notes: template
          ? `Automatically generated from ${template.title} for estimate ${estimate.title}.`
          : `Automatically generated from estimate ${estimate.title}.`,
      });

      await createDocument(client, {
        company_id: estimate.company_id,
        customer_id: estimate.customer_id,
        estimate_id: estimate.id,
        title: `${savedScope.title} - PDF Ready`,
        category: "scope",
        status: "draft",
        template_key:
          estimate.service_type === "painting" || isPaintingCompany(company)
            ? "ihc_scope_of_work"
            : "weathertech_scope_of_work",
        body: `# ${savedScope.title}\n\nPrepared by ${
          company?.name ?? "WeatherTech OS"
        }\n\n${savedScope.scope_body}`,
      });

      await onReload();
      onNotice("Scope of Work generated and saved to documents.");
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to generate scope of work."));
    }
  };

  const handleRequestEstimateSignature = async (estimate: EstimateRecord) => {
    const existingDocument =
      snapshot.documents.find(
        (document) =>
          document.estimate_id === estimate.id && document.category === "estimate",
      ) ?? null;
    const document =
      existingDocument ??
      (() => {
        const documentDraft = buildGeneratedDocumentDraft(
          snapshot,
          `estimate:${estimate.id}`,
        );
        return documentDraft;
      })();

    if (!document) {
      onError("Generate or save the estimate packet before requesting a signature.");
      return;
    }

    try {
      const savedDocument =
        "id" in document ? document : await createDocument(client, document);
      const existingSignature = snapshot.signatures.find(
        (signature) =>
          signature.document_id === savedDocument.id && signature.status !== "declined",
      );

      if (existingSignature) {
        onNotice("This estimate packet already has an active signature request.");
        return;
      }

      const association = getAssociationSummary(snapshot, {
        customerId: estimate.customer_id,
        leadId: estimate.lead_id,
        estimateId: estimate.id,
      });
      const customer = estimate.customer_id
        ? snapshot.customers.find((item) => item.id === estimate.customer_id)
        : null;
      const lead = estimate.lead_id
        ? snapshot.leads.find((item) => item.id === estimate.lead_id)
        : null;

      await createSignature(client, {
        company_id: estimate.company_id,
        customer_id: estimate.customer_id,
        document_id: savedDocument.id,
        signer_name:
          association.name && association.name !== "Unassigned"
            ? association.name
            : "Customer signer",
        signer_email: customer?.email ?? lead?.email ?? null,
        status: "pending",
      });

      await onReload();
      onNotice("Customer signature requested for the estimate packet.");
    } catch (currentError) {
      onError(getCaughtErrorMessage(currentError, "Unable to request customer signature."));
    }
  };

  return (
    <div className="space-y-5">
      <section
        id="estimate-builder"
        className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm scroll-mt-5"
      >
        <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
          <div>
            <p className="text-sm font-semibold uppercase text-sky-700">
              Estimate Builder
            </p>
            <h2 className="mt-1 text-xl font-bold text-slate-950">
              {selectedEstimate ? "Edit estimate" : "Create draft estimate"}
            </h2>
            <p className="mt-1 text-sm text-slate-500">
              Build a priced draft with scope, line items, and live totals before sending.
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-2">
            <Badge
              label={
                selectedEstimate
                  ? estimateStatusLabel(selectedEstimate.status)
                  : "Draft mode"
              }
              tone={isCreatingEstimate ? "amber" : "blue"}
            />
            {selectedEstimate ? (
              <button
                type="button"
                onClick={handleStartNewEstimate}
                className="inline-flex items-center justify-center gap-2 rounded-md bg-sky-600 px-3 py-2 text-sm font-semibold text-white transition hover:bg-sky-700"
              >
                <Plus className="h-4 w-4" />
                New Estimate
              </button>
            ) : null}
          </div>
        </div>
        <EstimateEditor
          key={selectedEstimate?.id ?? `new-estimate-${estimateDraftVersion}`}
          estimate={selectedEstimate}
          lineItems={selectedLineItems}
          snapshot={snapshot}
          onSave={handleSaveEstimate}
        />
      </section>

      <div className="grid gap-5 xl:grid-cols-[minmax(0,1fr)_420px]">
        <section className="min-w-0 rounded-lg border border-slate-200 bg-white shadow-sm">
          <div className="border-b border-slate-200 p-5">
            <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
              <div>
                <h2 className="text-xl font-bold text-slate-950">Estimates</h2>
                <p className="mt-1 text-sm text-slate-500">
                  Create priced proposals with labor, materials, tax, discounts, and margin.
                </p>
              </div>
              <div className="flex flex-col gap-2 sm:flex-row">
                <div className="relative">
                  <Search className="pointer-events-none absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                  <input
                    value={search}
                    onChange={(event) => setSearch(event.target.value)}
                    className="w-full rounded-md border border-slate-300 py-2 pl-9 pr-3 text-sm outline-none transition focus:border-sky-500 focus:ring-2 focus:ring-sky-100 sm:w-72"
                    placeholder="Search estimates"
                  />
                </div>
                <select
                  value={statusFilter}
                  onChange={(event) =>
                    setStatusFilter(event.target.value as EstimateStatus | "all")
                  }
                  className="rounded-md border border-slate-300 px-3 py-2 text-sm outline-none transition focus:border-sky-500 focus:ring-2 focus:ring-sky-100"
                >
                  <option value="all">All statuses</option>
                  {estimateStatuses.map((status) => (
                    <option key={status.value} value={status.value}>
                      {status.label}
                    </option>
                  ))}
                </select>
                <button
                  type="button"
                  onClick={handleStartNewEstimate}
                  className="inline-flex items-center justify-center gap-2 rounded-md bg-sky-600 px-3 py-2 text-sm font-semibold text-white transition hover:bg-sky-700"
                >
                  <Plus className="h-4 w-4" />
                  New Estimate
                </button>
              </div>
            </div>
          </div>

          <div className="divide-y divide-slate-100">
            {pagedEstimates.map((estimate) => (
              <button
                key={estimate.id}
                type="button"
                onClick={() => handleSelectEstimate(estimate.id)}
                className={`grid w-full cursor-pointer gap-3 border-l-4 px-5 py-4 text-left transition hover:bg-slate-50 focus:outline-none focus-visible:ring-2 focus-visible:ring-sky-300 xl:grid-cols-[1fr_130px_140px_120px] xl:items-center ${
                  selectedEstimate?.id === estimate.id
                    ? "border-l-sky-500 bg-sky-50"
                    : "border-l-transparent bg-white"
                }`}
              >
                <div>
                  <p className="font-semibold text-slate-950">{estimate.title}</p>
                  <p className="mt-1 text-sm text-slate-500">
                    {getEstimateTargetName(snapshot, estimate)}
                  </p>
                </div>
                <Badge label={estimateStatusLabel(estimate.status)} tone="blue" />
                <span className="text-sm text-slate-600">
                  {estimate.business ??
                    companyMap.get(estimate.company_id)?.name ??
                    "Company"}
                </span>
                <span className="text-sm font-semibold text-slate-950">
                  {formatMoney(estimate.total)}
                </span>
              </button>
            ))}

            {!filteredEstimates.length ? (
              <EmptyState label="No estimates match this view." />
            ) : null}
          </div>
          <PaginationControls
            page={estimatePage}
            pageCount={estimatePageCount}
            total={filteredEstimates.length}
            onPageChange={setEstimatePage}
          />
        </section>

        <aside className="space-y-5">
          <EstimatePdfPreview
            estimate={selectedEstimate}
            lineItems={selectedLineItems}
            snapshot={snapshot}
            company={selectedEstimate ? companyMap.get(selectedEstimate.company_id) : undefined}
          />
          <EstimateWorkflowPanel
            snapshot={snapshot}
            estimate={selectedEstimate}
            linkedJob={selectedEstimateJob}
            linkedScope={selectedEstimateScope}
            documents={selectedEstimateDocuments}
            signatures={selectedEstimateSignatures}
            onCreateJob={handleCreateJobFromEstimate}
            onSaveDocument={handleSaveEstimateDocument}
            onGenerateScope={handleGenerateScopeFromEstimate}
            onRequestSignature={handleRequestEstimateSignature}
          />
        </aside>
      </div>
    </div>
  );
}

function buildDefaultEstimateLineItems(
  serviceType: ServiceType,
): EstimateLineItemInput[] {
  if (serviceType === "painting") {
    return [
      {
        category: "labor",
        name: "Painting prep and application labor",
        description:
          "Masking, surface preparation, application, cleanup, and touch-up labor.",
        quantity: 1,
        unit: "project",
        unit_cost: 0,
        markup_rate: 0,
        taxable: false,
        sort_order: 0,
      },
      {
        category: "material",
        name: "Dunn-Edwards coating system and sundries",
        description:
          "Primer, finish paint, masking supplies, caulk, rollers, and sprayer consumables.",
        quantity: 1,
        unit: "package",
        unit_cost: 0,
        markup_rate: 15,
        taxable: true,
        sort_order: 1,
      },
    ];
  }

  return [
    {
      category: "labor",
      name: "Labor",
      description: "",
      quantity: 1,
      unit: "project",
      unit_cost: 0,
      markup_rate: 0,
      taxable: false,
      sort_order: 0,
    },
    {
      category: "material",
      name: "Materials",
      description: "",
      quantity: 1,
      unit: "package",
      unit_cost: 0,
      markup_rate: 0,
      taxable: true,
      sort_order: 1,
    },
  ];
}

function cloneEstimateTemplateLineItems(template: EstimateTemplate) {
  return template.lineItems.map((item, index) => ({
    ...item,
    description: item.description ?? "",
    unit: item.unit ?? "each",
    unit_price: item.unit_price ?? item.unit_cost,
    markup_rate: item.markup_rate ?? 0,
    taxable: item.taxable ?? true,
    sort_order: index,
  }));
}

function getTemplateDefaultTitle(template: EstimateTemplate) {
  return `${template.name} Proposal`;
}

function getEstimateScopeCategory(estimate: EstimateRecord): ScopeCategory {
  if (estimate.service_type === "painting") {
    if (estimate.painting_area_type === "interior") {
      return "interior_painting";
    }

    if (estimate.painting_area_type === "cabinet") {
      return "cabinet_refinishing";
    }

    return "exterior_painting";
  }

  if (/repair/i.test(estimate.title)) {
    return "roof_repairs";
  }

  if (/tile|underlayment/i.test(estimate.title)) {
    return "tile_underlayment";
  }

  return "roofing";
}

function selectScopeTemplateForEstimate(
  snapshot: CrmSnapshot,
  estimate: EstimateRecord,
) {
  const category = getEstimateScopeCategory(estimate);

  return (
    snapshot.scopeTemplates.find(
      (template) =>
        template.category === category && template.company_id === estimate.company_id,
    ) ??
    snapshot.scopeTemplates.find(
      (template) => template.category === category && template.company_id === null,
    ) ??
    snapshot.scopeTemplates.find((template) => template.company_id === estimate.company_id) ??
    null
  );
}

function buildScopeBodyFromEstimate(
  snapshot: CrmSnapshot,
  estimate: EstimateRecord,
  lineItems: EstimateLineItemRecord[],
  template: ScopeTemplateRecord | null,
) {
  const customer = estimate.customer_id
    ? snapshot.customers.find((item) => item.id === estimate.customer_id)
    : null;
  const lead = estimate.lead_id
    ? snapshot.leads.find((item) => item.id === estimate.lead_id)
    : null;
  const propertyAddress =
    estimate.location ??
    customer?.property_address ??
    lead?.property_address ??
    "Property address to confirm";
  const company = snapshot.companies.find((item) => item.id === estimate.company_id);
  const businessName = getEstimateBusinessName(
    snapshot,
    estimate.company_id,
    estimate.business,
  );
  const templateBody =
    template?.template_body ??
    "1. Confirm customer expectations, access, and approved proposal details.\n2. Protect property and prepare work areas before production.\n3. Complete approved work according to company standards and documented scope.\n4. Clean work areas, capture final photos, and complete customer walkthrough.";
  const itemList = lineItems.length
    ? lineItems
        .map(
          (item) =>
            `- ${item.name}: ${item.quantity} ${item.unit} at ${formatMoney(item.unit_cost)} (${formatMoney(item.total)})`,
        )
        .join("\n")
    : "- Estimate line items to be confirmed.";
  const paintingSpecs =
    estimate.service_type === "painting"
      ? [
          "",
          "Painting specifications:",
          `- Product: ${estimate.paint_product_line ?? estimate.paint_brand}`,
          `- Finish / sheen: ${paintFinishLabel(estimate.paint_finish)}`,
          `- Surface prep: ${surfacePrepLabel(estimate.surface_prep_level)}`,
          `- Color status: ${colorSelectionStatusLabel(estimate.color_selection_status)}`,
          `- Body / wall color: ${estimate.paint_color_body ?? "Not set"}`,
          `- Trim color: ${estimate.paint_color_trim ?? "Not set"}`,
          `- Accent / cabinet color: ${estimate.paint_color_accent ?? "Not set"}`,
          `- Coats / primer: ${estimate.coats} coats / ${
            estimate.primer_required ? "primer required" : "primer not required"
          }`,
        ].join("\n")
      : "";

  return [
    templateBody,
    "",
    "Project-specific details:",
    `- Company: ${businessName}`,
    `- Estimate: ${estimate.title}`,
    `- Customer: ${getEstimateTargetName(snapshot, estimate)}`,
    `- Property: ${propertyAddress}`,
    `- Approved total: ${formatMoney(estimate.total)}`,
    `- Service type: ${serviceLabel(estimate.service_type)}`,
    paintingSpecs,
    "",
    "Included estimate line items:",
    itemList,
    estimate.scope_of_work ? "\nSaved estimate scope of work:" : "",
    estimate.scope_of_work ?? "",
    "",
    "Customer expectations:",
    "- Scope is based on the approved estimate, selected materials, approved colors where applicable, and documented site conditions.",
    "- Changes to hidden conditions, material selections, colors, or access requirements require written approval before production.",
    "- Final walkthrough, cleanup, and document/photos closeout are included in the production handoff.",
  ]
    .filter(Boolean)
    .join("\n");
}

function EstimateEditor({
  estimate,
  lineItems,
  snapshot,
  onSave,
}: {
  estimate: EstimateRecord | null;
  lineItems: EstimateLineItemRecord[];
  snapshot: CrmSnapshot;
  onSave: (input: EstimateInput, lineItems: EstimateLineItemInput[]) => Promise<void>;
}) {
  const initialCompanyId = estimate?.company_id ?? snapshot.companies[0]?.id ?? "";
  const initialCompany =
    snapshot.companies.find((company) => company.id === initialCompanyId) ?? null;
  const initialServiceType =
    estimate?.service_type ?? (isPaintingCompany(initialCompany) ? "painting" : "roofing");
  const initialBusiness = getEstimateBusinessName(
    snapshot,
    initialCompanyId,
    estimate?.business,
  );
  const initialLocation =
    estimate?.location ??
    getAssociationLocation(snapshot, estimate?.customer_id ?? null, estimate?.lead_id ?? null);
  const [draftLineItems, setDraftLineItems] = useState<EstimateLineItemInput[]>(
    lineItems.length
      ? lineItems.map((item) => ({
          id: item.id,
          category: item.category,
          name: item.name,
          description: item.description,
          quantity: item.quantity,
          unit: item.unit,
          unit_cost: item.unit_cost,
          unit_price: item.unit_price ?? item.unit_cost,
          markup_rate: item.markup_rate,
          taxable: item.taxable,
          sort_order: item.sort_order,
        }))
      : buildDefaultEstimateLineItems(initialServiceType),
  );
  const [selectedCompanyId, setSelectedCompanyId] = useState(initialCompanyId);
  const [selectedServiceType, setSelectedServiceType] =
    useState<ServiceType>(initialServiceType);
  const [draftTitle, setDraftTitle] = useState(estimate?.title ?? "");
  const [draftBusiness, setDraftBusiness] = useState(initialBusiness);
  const [draftLocation, setDraftLocation] = useState(initialLocation);
  const [draftStatus, setDraftStatus] = useState<EstimateStatus>(
    estimate?.status ?? "draft",
  );
  const [draftCustomerId, setDraftCustomerId] = useState(
    estimate?.customer_id ?? "none",
  );
  const [draftLeadId, setDraftLeadId] = useState(estimate?.lead_id ?? "none");
  const [draftIssueDate, setDraftIssueDate] = useState(
    estimate?.issue_date ?? todayIsoDate(),
  );
  const [draftExpirationDate, setDraftExpirationDate] = useState(
    estimate?.expiration_date ?? addDaysIsoDate(30),
  );
  const [draftNotes, setDraftNotes] = useState(estimate?.notes ?? "");
  const [draftScopeOfWork, setDraftScopeOfWork] = useState(
    estimate?.scope_of_work ?? "",
  );
  const [selectedColorStatus, setSelectedColorStatus] =
    useState<ColorSelectionStatus>(
      estimate?.color_selection_status ?? "not_started",
    );
  const [paintingFields, setPaintingFields] = useState({
    painting_area_type: estimate?.painting_area_type ?? "exterior",
    paint_product_line: estimate?.paint_product_line ?? dunnEdwardsProductLines[0],
    paint_finish: estimate?.paint_finish ?? "satin",
    paint_color_body: estimate?.paint_color_body ?? "",
    paint_color_trim: estimate?.paint_color_trim ?? "",
    paint_color_accent: estimate?.paint_color_accent ?? "",
    surface_prep_level: estimate?.surface_prep_level ?? "standard",
    coats: estimate?.coats ?? 2,
    primer_required: estimate?.primer_required ?? false,
  });
  const [estimateControls, setEstimateControls] = useState({
    tax_rate: estimate?.tax_rate ?? 8.6,
    discount_type: estimate?.discount_type ?? "fixed",
    discount_value: estimate?.discount_value ?? 0,
    profit_margin_rate: estimate?.profit_margin_rate ?? 10,
  });
  const [isSaving, setIsSaving] = useState(false);
  const liveTotals = calculateEstimateTotals(estimateControls, draftLineItems);
  const selectedCompany =
    snapshot.companies.find((company) => company.id === selectedCompanyId) ?? null;
  const showPaintingWorkflow =
    selectedServiceType === "painting" || isPaintingCompany(selectedCompany);
  const availableEstimateTemplates = useMemo(
    () =>
      getEstimateTemplatesForTrade(
        selectedCompany?.workflow_profile ?? selectedCompany?.trade,
      ),
    [selectedCompany?.trade, selectedCompany?.workflow_profile],
  );
  const [selectedTemplateKey, setSelectedTemplateKey] = useState(
    availableEstimateTemplates[0]?.key ?? "",
  );
  const selectedTemplate =
    availableEstimateTemplates.find((template) => template.key === selectedTemplateKey) ??
    availableEstimateTemplates[0] ??
    null;

  useEffect(() => {
    if (
      availableEstimateTemplates.length &&
      !availableEstimateTemplates.some((template) => template.key === selectedTemplateKey)
    ) {
      setSelectedTemplateKey(availableEstimateTemplates[0].key);
    }
  }, [availableEstimateTemplates, selectedTemplateKey]);

  const updateLineItem = (
    index: number,
    updates: Partial<EstimateLineItemInput>,
  ) => {
    setDraftLineItems((items) =>
      items.map((item, itemIndex) =>
        itemIndex === index ? { ...item, ...updates } : item,
      ),
    );
  };

  const addLineItem = (category: EstimateLineItemCategory) => {
    setDraftLineItems((items) => [
      ...items,
      {
        category,
        name: category === "labor" ? "Labor item" : "Material item",
        description: "",
        quantity: 1,
        unit: category === "labor" ? "hour" : "each",
        unit_cost: 0,
        unit_price: 0,
        markup_rate: 0,
        taxable: category !== "labor",
        sort_order: items.length,
      },
    ]);
  };

  const addPaintingPackage = () => {
    setDraftLineItems((items) => [
      ...items,
      ...buildDefaultEstimateLineItems("painting").map((item, index) => ({
        ...item,
        sort_order: items.length + index,
      })),
    ]);
  };

  const applyEstimateTemplate = (template: EstimateTemplate) => {
    setSelectedServiceType(template.serviceType);
    setDraftTitle((current) =>
      estimate && current.trim() ? current : getTemplateDefaultTitle(template),
    );
    setDraftNotes(template.notes);
    setDraftScopeOfWork(
      [
        scopeCategoryLabels[template.scopeCategory],
        template.description,
        template.notes,
      ]
        .filter(Boolean)
        .join("\n\n"),
    );
    setDraftLineItems(cloneEstimateTemplateLineItems(template));
    setEstimateControls({
      tax_rate: template.taxRate,
      discount_type: template.discountType,
      discount_value: template.discountValue,
      profit_margin_rate: template.profitMarginRate,
    });

    if (template.painting) {
      setSelectedColorStatus("not_started");
      setPaintingFields((current) => ({
        ...current,
        painting_area_type: template.painting?.areaType ?? current.painting_area_type,
        paint_product_line: template.painting?.productLine ?? current.paint_product_line,
        paint_finish: template.painting?.finish ?? current.paint_finish,
        surface_prep_level:
          template.painting?.surfacePrepLevel ?? current.surface_prep_level,
        coats: template.painting?.coats ?? current.coats,
        primer_required: template.painting?.primerRequired ?? current.primer_required,
      }));
    }
  };

  const handleCompanyChange = (companyId: string) => {
    setSelectedCompanyId(companyId);
    const company = snapshot.companies.find((item) => item.id === companyId);
    setDraftBusiness(company?.name ?? "");
    const nextTemplates = getEstimateTemplatesForTrade(
      company?.workflow_profile ?? company?.trade,
    );

    if (nextTemplates[0]) {
      setSelectedTemplateKey(nextTemplates[0].key);
    }

    if (isPaintingCompany(company)) {
      setSelectedServiceType("painting");
      return;
    }

    if (company?.workflow_profile === "roofing" || company?.trade === "roofing") {
      setSelectedServiceType("roofing");
    }
  };

  const removeLineItem = (index: number) => {
    setDraftLineItems((items) => items.filter((_item, itemIndex) => itemIndex !== index));
  };

  const handleCustomerChange = (customerId: string) => {
    setDraftCustomerId(customerId);

    if (customerId !== "none") {
      const location = getAssociationLocation(snapshot, customerId, null);
      setDraftLocation(location || draftLocation);
    }
  };

  const handleLeadChange = (leadId: string) => {
    setDraftLeadId(leadId);

    if (leadId !== "none") {
      const location = getAssociationLocation(snapshot, null, leadId);
      setDraftLocation(location || draftLocation);
    }
  };

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const cleanLineItems = draftLineItems
      .filter((item) => item.name.trim())
      .map((item, index) => {
        const unitPrice = item.unit_price ?? item.unit_cost;

        return {
          ...item,
          unit_cost: unitPrice,
          unit_price: unitPrice,
          sort_order: index,
        };
      });

    try {
      setIsSaving(true);
      await onSave(
        {
          company_id: selectedCompanyId || snapshot.companies[0]?.id || "",
          customer_id: draftCustomerId === "none" ? null : draftCustomerId,
          lead_id: draftLeadId === "none" ? null : draftLeadId,
          business:
            draftBusiness.trim() ||
            getEstimateBusinessName(snapshot, selectedCompanyId, null),
          location: draftLocation.trim() || null,
          title: draftTitle.trim() || "New estimate",
          status: draftStatus,
          service_type: selectedServiceType,
          issue_date: draftIssueDate || todayIsoDate(),
          expiration_date: draftExpirationDate || null,
          tax_rate: estimateControls.tax_rate,
          discount_type: estimateControls.discount_type,
          discount_value: estimateControls.discount_value,
          profit_margin_rate: estimateControls.profit_margin_rate,
          notes: draftNotes.trim() || null,
          scope_of_work: draftScopeOfWork.trim() || null,
          painting_area_type: showPaintingWorkflow
            ? (paintingFields.painting_area_type as PaintingAreaType)
            : null,
          paint_brand: "Dunn-Edwards",
          paint_product_line: showPaintingWorkflow
            ? paintingFields.paint_product_line || null
            : null,
          paint_finish: showPaintingWorkflow
            ? (paintingFields.paint_finish as PaintFinish)
            : null,
          color_selection_status: showPaintingWorkflow
            ? selectedColorStatus
            : "not_started",
          paint_color_body: showPaintingWorkflow
            ? paintingFields.paint_color_body.trim() || null
            : null,
          paint_color_trim: showPaintingWorkflow
            ? paintingFields.paint_color_trim.trim() || null
            : null,
          paint_color_accent: showPaintingWorkflow
            ? paintingFields.paint_color_accent.trim() || null
            : null,
          surface_prep_level: showPaintingWorkflow
            ? (paintingFields.surface_prep_level as SurfacePrepLevel)
            : null,
          coats: showPaintingWorkflow
            ? Math.min(4, Math.max(1, Math.round(paintingFields.coats || 2)))
            : 2,
          primer_required: showPaintingWorkflow ? paintingFields.primer_required : false,
        },
        cleanLineItems,
      );
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="mt-5 grid gap-4">
      <div className="grid gap-3 sm:grid-cols-2">
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Company
          <select
            name="company_id"
            required
            value={selectedCompanyId}
            onChange={(event) => handleCompanyChange(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2"
          >
            {snapshot.companies.map((company) => (
              <option key={company.id} value={company.id}>
                {company.name}
              </option>
            ))}
          </select>
        </label>
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Status
          <select
            name="status"
            value={draftStatus}
            onChange={(event) => setDraftStatus(event.target.value as EstimateStatus)}
            className="rounded-md border border-slate-300 px-3 py-2"
          >
            {estimateStatuses.map((status) => (
              <option key={status.value} value={status.value}>
                {status.label}
              </option>
            ))}
          </select>
        </label>
      </div>

      <input
        required
        name="title"
        value={draftTitle}
        onChange={(event) => setDraftTitle(event.target.value)}
        className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Estimate title"
      />

      <div className="grid gap-3 sm:grid-cols-2">
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Business
          <input
            name="business"
            value={draftBusiness}
            onChange={(event) => setDraftBusiness(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2 text-sm"
            placeholder="Business"
          />
        </label>
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Location
          <input
            name="location"
            value={draftLocation}
            onChange={(event) => setDraftLocation(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2 text-sm"
            placeholder="Project location"
          />
        </label>
      </div>

      <div className="grid gap-3 sm:grid-cols-3">
        <select
          name="customer_id"
          value={draftCustomerId}
          onChange={(event) => handleCustomerChange(event.target.value)}
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        >
          <option value="none">No customer</option>
          {snapshot.customers.map((customer) => (
            <option key={customer.id} value={customer.id}>
              {customer.display_name}
            </option>
          ))}
        </select>
        <select
          name="lead_id"
          value={draftLeadId}
          onChange={(event) => handleLeadChange(event.target.value)}
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        >
          <option value="none">No lead</option>
          {snapshot.leads.map((lead) => (
            <option key={lead.id} value={lead.id}>
              {lead.contact_name}
            </option>
          ))}
        </select>
        <select
          name="service_type"
          value={selectedServiceType}
          onChange={(event) => setSelectedServiceType(event.target.value as ServiceType)}
          className="rounded-md border border-slate-300 px-3 py-2 text-sm"
        >
          {serviceTypes.map((service) => (
            <option key={service.value} value={service.value}>
              {service.label}
            </option>
          ))}
        </select>
      </div>

      <div className="grid gap-3 sm:grid-cols-2">
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Issue date
          <input
            name="issue_date"
            type="date"
            value={draftIssueDate}
            onChange={(event) => setDraftIssueDate(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2"
          />
        </label>
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Expiration date
          <input
            name="expiration_date"
            type="date"
            value={draftExpirationDate}
            onChange={(event) => setDraftExpirationDate(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2"
          />
        </label>
      </div>

      <section className="grid gap-3 rounded-lg border border-slate-200 bg-white p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <p className="text-sm font-bold text-slate-950">Reusable estimate template</p>
            <p className="mt-1 text-sm text-slate-500">
              Load company-specific proposal structure, line items, financial defaults, and scope category.
            </p>
          </div>
          <Badge
            label={selectedCompany?.short_name ?? selectedCompany?.name ?? "Company"}
            tone="blue"
          />
        </div>
        <div className="grid gap-3 sm:grid-cols-[minmax(0,1fr)_auto]">
          <select
            value={selectedTemplateKey}
            onChange={(event) => setSelectedTemplateKey(event.target.value)}
            className="rounded-md border border-slate-300 px-3 py-2 text-sm"
          >
            {availableEstimateTemplates.map((template) => (
              <option key={template.key} value={template.key}>
                {template.name}
              </option>
            ))}
          </select>
          <button
            type="button"
            onClick={() => selectedTemplate && applyEstimateTemplate(selectedTemplate)}
            disabled={!selectedTemplate}
            className="inline-flex items-center justify-center gap-2 rounded-md border border-slate-300 bg-slate-950 px-3 py-2 text-sm font-semibold text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-300"
          >
            <Copy className="h-4 w-4" />
            Apply template
          </button>
        </div>
        {selectedTemplate ? (
          <div className="rounded-md bg-slate-50 p-3 text-sm text-slate-600">
            <p className="font-semibold text-slate-800">{selectedTemplate.description}</p>
            <p className="mt-1">
              Scope: {scopeCategoryLabels[selectedTemplate.scopeCategory]} · Margin{" "}
              {selectedTemplate.profitMarginRate}% · Tax {selectedTemplate.taxRate}%
            </p>
          </div>
        ) : null}
      </section>

      {showPaintingWorkflow ? (
        <section className="grid gap-4 rounded-lg border border-violet-100 bg-violet-50/60 p-4">
          <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <p className="inline-flex items-center gap-2 text-sm font-bold text-slate-950">
                <Paintbrush className="h-4 w-4 text-violet-700" />
                IHC painting details
              </p>
              <p className="mt-1 text-sm text-slate-600">
                Dunn-Edwards products, finish schedule, color approvals, and prep requirements.
              </p>
            </div>
            <Badge label={colorSelectionStatusLabel(selectedColorStatus)} tone="blue" />
          </div>

          <div className="grid gap-3 md:grid-cols-3">
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Project area
              <select
                name="painting_area_type"
                value={paintingFields.painting_area_type}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    painting_area_type: event.target.value as PaintingAreaType,
                  }))
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              >
                {paintingAreaTypes.map((area) => (
                  <option key={area.value} value={area.value}>
                    {area.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Product line
              <select
                name="paint_product_line"
                value={paintingFields.paint_product_line}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    paint_product_line: event.target.value,
                  }))
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              >
                {dunnEdwardsProductLines.map((product) => (
                  <option key={product} value={product}>
                    {product}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Finish / sheen
              <select
                name="paint_finish"
                value={paintingFields.paint_finish}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    paint_finish: event.target.value as PaintFinish,
                  }))
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              >
                {paintFinishOptions.map((finish) => (
                  <option key={finish.value} value={finish.value}>
                    {finish.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Color status
              <select
                value={selectedColorStatus}
                onChange={(event) =>
                  setSelectedColorStatus(event.target.value as ColorSelectionStatus)
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              >
                {colorSelectionStatuses.map((status) => (
                  <option key={status.value} value={status.value}>
                    {status.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Surface prep
              <select
                name="surface_prep_level"
                value={paintingFields.surface_prep_level}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    surface_prep_level: event.target.value as SurfacePrepLevel,
                  }))
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              >
                {surfacePrepLevels.map((level) => (
                  <option key={level.value} value={level.value}>
                    {level.label}
                  </option>
                ))}
              </select>
            </label>
            <label className="grid gap-1 text-sm font-medium text-slate-700">
              Coats
              <input
                name="coats"
                type="number"
                min="1"
                max="4"
                value={paintingFields.coats}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    coats: Number(event.target.value) || 2,
                  }))
                }
                className="rounded-md border border-slate-300 px-3 py-2"
              />
            </label>
          </div>

          <input type="hidden" name="paint_brand" value="Dunn-Edwards" />
          <div className="grid gap-3 md:grid-cols-3">
            <input
              name="paint_color_body"
              value={paintingFields.paint_color_body}
              onChange={(event) =>
                setPaintingFields((current) => ({
                  ...current,
                  paint_color_body: event.target.value,
                }))
              }
              className="rounded-md border border-slate-300 px-3 py-2 text-sm"
              placeholder="Body / wall color"
            />
            <input
              name="paint_color_trim"
              value={paintingFields.paint_color_trim}
              onChange={(event) =>
                setPaintingFields((current) => ({
                  ...current,
                  paint_color_trim: event.target.value,
                }))
              }
              className="rounded-md border border-slate-300 px-3 py-2 text-sm"
              placeholder="Trim color"
            />
            <input
              name="paint_color_accent"
              value={paintingFields.paint_color_accent}
              onChange={(event) =>
                setPaintingFields((current) => ({
                  ...current,
                  paint_color_accent: event.target.value,
                }))
              }
              className="rounded-md border border-slate-300 px-3 py-2 text-sm"
              placeholder="Accent / cabinet color"
            />
          </div>

          <div className="grid gap-3 md:grid-cols-[1fr_220px]">
            <div className="grid gap-2 rounded-md border border-violet-100 bg-white p-3">
              <p className="inline-flex items-center gap-2 text-xs font-bold uppercase tracking-wide text-slate-500">
                <Palette className="h-4 w-4 text-violet-700" />
                Color workflow
              </p>
              <div className="grid gap-2 sm:grid-cols-4">
                {colorSelectionStatuses.map((status) => {
                  const isActive = status.value === selectedColorStatus;

                  return (
                    <div
                      key={status.value}
                      className={`rounded-md border px-3 py-2 text-xs font-semibold ${
                        isActive
                          ? "border-violet-300 bg-violet-100 text-violet-900"
                          : "border-slate-200 bg-slate-50 text-slate-600"
                      }`}
                    >
                      {status.label}
                    </div>
                  );
                })}
              </div>
            </div>
            <label className="flex items-center justify-center gap-2 rounded-md border border-violet-100 bg-white px-3 py-3 text-sm font-semibold text-slate-700">
              <input
                name="primer_required"
                type="checkbox"
                checked={paintingFields.primer_required}
                onChange={(event) =>
                  setPaintingFields((current) => ({
                    ...current,
                    primer_required: event.target.checked,
                  }))
                }
              />
              Primer required
            </label>
          </div>
        </section>
      ) : null}

      <div className="grid gap-3 rounded-lg border border-slate-200 bg-slate-50 p-3 sm:grid-cols-4">
        <NumberControl
          label="Tax %"
          value={estimateControls.tax_rate}
          onChange={(value) =>
            setEstimateControls((controls) => ({ ...controls, tax_rate: value }))
          }
        />
        <label className="grid gap-1 text-sm font-medium text-slate-700">
          Discount
          <select
            value={estimateControls.discount_type}
            onChange={(event) =>
              setEstimateControls((controls) => ({
                ...controls,
                discount_type: event.target.value as "fixed" | "percent",
              }))
            }
            className="rounded-md border border-slate-300 px-3 py-2"
          >
            <option value="fixed">Fixed</option>
            <option value="percent">Percent</option>
          </select>
        </label>
        <NumberControl
          label="Discount value"
          value={estimateControls.discount_value}
          onChange={(value) =>
            setEstimateControls((controls) => ({ ...controls, discount_value: value }))
          }
        />
        <NumberControl
          label="Profit %"
          value={estimateControls.profit_margin_rate}
          onChange={(value) =>
            setEstimateControls((controls) => ({
              ...controls,
              profit_margin_rate: value,
            }))
          }
        />
      </div>

      <div className="rounded-lg border border-slate-200">
        <div className="flex items-center justify-between border-b border-slate-200 p-3">
          <p className="text-sm font-bold text-slate-950">Line items</p>
          <div className="flex flex-wrap gap-2">
            {showPaintingWorkflow ? (
              <button
                type="button"
                onClick={addPaintingPackage}
                className="inline-flex items-center gap-1 rounded-md border border-violet-200 bg-violet-50 px-2.5 py-1.5 text-xs font-semibold text-violet-800 hover:bg-violet-100"
              >
                <Paintbrush className="h-3.5 w-3.5" />
                Painting package
              </button>
            ) : null}
            {lineItemCategories.map((category) => (
              <button
                key={category.value}
                type="button"
                onClick={() => addLineItem(category.value)}
                className="rounded-md border border-slate-300 bg-white px-2.5 py-1.5 text-xs font-semibold text-slate-700 hover:bg-slate-50"
              >
                Add {category.label}
              </button>
            ))}
          </div>
        </div>
        <div className="grid gap-3 p-3">
          {draftLineItems.map((item, index) => (
            <div key={`${item.id ?? "new"}-${index}`} className="rounded-lg bg-slate-50 p-3">
              <div className="grid gap-2 sm:grid-cols-[120px_1fr_88px_92px_92px_72px_40px]">
                <select
                  value={item.category}
                  onChange={(event) =>
                    updateLineItem(index, {
                      category: event.target.value as EstimateLineItemCategory,
                    })
                  }
                  className="rounded-md border border-slate-300 px-2 py-2 text-sm"
                >
                  {lineItemCategories.map((category) => (
                    <option key={category.value} value={category.value}>
                      {category.label}
                    </option>
                  ))}
                </select>
                <input
                  value={item.name}
                  onChange={(event) => updateLineItem(index, { name: event.target.value })}
                  className="rounded-md border border-slate-300 px-2 py-2 text-sm"
                  placeholder="Item name"
                />
                <input
                  value={item.quantity}
                  onChange={(event) =>
                    updateLineItem(index, { quantity: Number(event.target.value) || 0 })
                  }
                  className="rounded-md border border-slate-300 px-2 py-2 text-sm"
                  inputMode="decimal"
                  placeholder="Qty"
                />
                <input
                  value={item.unit}
                  onChange={(event) => updateLineItem(index, { unit: event.target.value })}
                  className="rounded-md border border-slate-300 px-2 py-2 text-sm"
                  placeholder="Unit"
                />
                <input
                  value={item.unit_price ?? item.unit_cost}
                  onChange={(event) =>
                    updateLineItem(index, {
                      unit_cost: Number(event.target.value) || 0,
                      unit_price: Number(event.target.value) || 0,
                    })
                  }
                  className="rounded-md border border-slate-300 px-2 py-2 text-sm"
                  inputMode="decimal"
                  placeholder="Price"
                />
                <label className="flex items-center justify-center gap-2 rounded-md border border-slate-300 bg-white px-2 py-2 text-xs font-semibold text-slate-600">
                  <input
                    type="checkbox"
                    checked={item.taxable ?? true}
                    onChange={(event) =>
                      updateLineItem(index, { taxable: event.target.checked })
                    }
                  />
                  Tax
                </label>
                <button
                  type="button"
                  onClick={() => removeLineItem(index)}
                  className="grid place-items-center rounded-md border border-slate-300 bg-white text-slate-500 hover:bg-red-50 hover:text-red-700"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
              </div>
              <textarea
                value={item.description ?? ""}
                onChange={(event) =>
                  updateLineItem(index, { description: event.target.value })
                }
                className="mt-2 min-h-16 w-full rounded-md border border-slate-300 px-2 py-2 text-sm"
                placeholder="Description"
              />
              <p className="mt-2 text-right text-sm font-semibold text-slate-700">
                Line total: {formatMoney(calculateLineItemTotal(item))}
              </p>
            </div>
          ))}
        </div>
      </div>

      <div className="rounded-lg border border-slate-200 bg-slate-50 p-4">
        <div className="grid gap-2 text-sm">
          <TotalRow label="Labor" value={liveTotals.laborTotal} />
          <TotalRow label="Materials" value={liveTotals.materialTotal} />
          <TotalRow label="Subtotal" value={liveTotals.subtotal} />
          <TotalRow label="Discount" value={-liveTotals.discountTotal} />
          <TotalRow label="Tax" value={liveTotals.taxTotal} />
          <TotalRow label="Profit margin" value={liveTotals.profitMarginTotal} />
          <TotalRow label="Total" value={liveTotals.total} strong />
        </div>
      </div>

      <textarea
        name="scope_of_work"
        value={draftScopeOfWork}
        onChange={(event) => setDraftScopeOfWork(event.target.value)}
        className="min-h-28 rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Scope of work"
      />

      <textarea
        name="notes"
        value={draftNotes}
        onChange={(event) => setDraftNotes(event.target.value)}
        className="min-h-24 rounded-md border border-slate-300 px-3 py-2 text-sm"
        placeholder="Estimate notes"
      />

      <button
        type="submit"
        disabled={isSaving}
        className="inline-flex items-center justify-center gap-2 rounded-md bg-slate-950 px-4 py-2 text-sm font-semibold text-white hover:bg-slate-800 disabled:cursor-not-allowed disabled:bg-slate-300"
      >
        <FileText className="h-4 w-4" />
        {isSaving ? "Saving" : estimate ? "Save estimate" : "Create estimate"}
      </button>
    </form>
  );
}

function NumberControl({
  label,
  value,
  onChange,
}: {
  label: string;
  value: number;
  onChange: (value: number) => void;
}) {
  return (
    <label className="grid gap-1 text-sm font-medium text-slate-700">
      {label}
      <input
        value={value}
        onChange={(event) => onChange(Number(event.target.value) || 0)}
        className="rounded-md border border-slate-300 px-3 py-2"
        inputMode="decimal"
      />
    </label>
  );
}

function TotalRow({
  label,
  value,
  strong,
}: {
  label: string;
  value: number;
  strong?: boolean;
}) {
  return (
    <div
      className={`flex items-center justify-between ${
        strong ? "border-t border-slate-200 pt-2 text-base font-bold" : ""
      }`}
    >
      <span>{label}</span>
      <span>{formatMoney(value)}</span>
    </div>
  );
}

