function getTwilioReadinessTone(status: TwilioLiveReadinessStatus): ProviderBadgeTone {
  if (status === "backend_ready" || status === "ready_for_live_test" || status === "connected") {
    return "green";
  }

  if (status === "error") {
    return "red";
  }

  if (status === "not_connected") {
    return "slate";
  }

  return "amber";
}

