function IntegrationConnectionDialog({
  workflow,
  action,
  onClose,
}: {
  workflow: IntegrationConnectionWorkflow;
  action: IntegrationConnectionAction;
  onClose: () => void;
}) {
  const { provider } = workflow;
  const actionLabel = integrationConnectionActionLabel(action);
  const isDisconnect = action === "disconnect";
  const isReconnect = action === "reconnect";

  return (
    <div
      className="fixed inset-0 z-50 grid place-items-end bg-slate-950/40 p-0 sm:place-items-center sm:p-4"
      role="presentation"
    >
      <section
        aria-label={`${provider.metadata.label} ${actionLabel}`}
        aria-modal="true"
        className="max-h-[92vh] w-full overflow-y-auto rounded-t-xl bg-white shadow-2xl sm:max-w-4xl sm:rounded-xl"
        data-testid="integration-connection-dialog"
        role="dialog"
      >
        <div className="sticky top-0 z-10 flex items-start justify-between gap-4 border-b border-slate-200 bg-white p-5">
          <div>
            <p className="text-sm font-semibold uppercase text-sky-700">
              {actionLabel}
            </p>
            <h3 className="mt-1 text-xl font-bold text-slate-950">
              {provider.metadata.label}
            </h3>
            <p className="mt-1 text-sm leading-6 text-slate-500">
              {workflow.statusSummary}
            </p>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="rounded-md border border-slate-300 p-2 text-slate-500 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-sky-500 focus:ring-offset-2"
            aria-label="Close integration connection dialog"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="grid gap-5 p-5">
          <IntegrationNoticeBanner title="Architecture Only" tone="blue">
            This workflow does not connect a live account, validate credentials,
            send messages, sync records, or disconnect anything. Live provider
            operations must run through future server-side handlers after owner
            approval.
          </IntegrationNoticeBanner>

          {provider.healthState === "needs_attention" ? (
            <IntegrationNoticeBanner title="Error State" tone="red">
              Existing records indicate this provider needs attention before a
              live workflow can run. Review provider errors and retry history
              before enabling connectivity.
            </IntegrationNoticeBanner>
          ) : null}

          {isDisconnect ? (
            <IntegrationNoticeBanner title="Disconnect Flow" tone="amber">
              {provider.metadata.disconnectSummary} No live disconnect action is
              available from this architecture preview.
            </IntegrationNoticeBanner>
          ) : null}

          {isReconnect ? (
            <IntegrationNoticeBanner title="Reconnect Flow" tone="amber">
              {provider.metadata.reconnectSummary} No live reconnect action is
              available from this architecture preview.
            </IntegrationNoticeBanner>
          ) : null}

          <IntegrationWorkflowSummary workflow={workflow} />
          <IntegrationConnectionWizard workflow={workflow} />
          <IntegrationConfigurationPage workflow={workflow} />
          <IntegrationCredentialValidationPanel workflow={workflow} />
          <IntegrationOAuthReadinessPanel workflow={workflow} />

          <div className="grid gap-3">
            <h4 className="text-sm font-bold uppercase text-slate-500">
              Capability Summary
            </h4>
            <ProviderCapabilityPills provider={provider} />
          </div>

          <div className="flex flex-col gap-3 border-t border-slate-200 pt-4 sm:flex-row sm:items-center sm:justify-between">
            <p className="text-sm leading-6 text-slate-500">
              Live connectivity is disabled in this sprint.
            </p>
            <button
              type="button"
              disabled
              className="inline-flex min-h-10 items-center justify-center rounded-md bg-slate-200 px-4 py-2 text-sm font-bold text-slate-500"
            >
              Live action unavailable
            </button>
          </div>
        </div>
      </section>
    </div>
  );
}

function IntegrationProviderCard({
  provider,
  onOpenWorkflow,
}: {
  provider: IntegrationProviderReadiness;
  onOpenWorkflow: (
    providerId: IntegrationProviderId,
    action: IntegrationConnectionAction,
  ) => void;
}) {
  const Icon = integrationProviderIconMap[provider.metadata.iconKey];
  const workflow = buildIntegrationConnectionWorkflow(provider);
  const connectionTone = provider.connectionState === "connected" ? "green" : "blue";
  const readinessTone = getReadinessTone(provider.readinessState);

  return (
    <article
      className="grid gap-4 rounded-lg border border-slate-200 bg-slate-50 p-4"
      data-provider-id={provider.metadata.id}
      data-testid="integration-provider-card"
    >
      <div className="flex items-start justify-between gap-3">
        <div className="flex items-start gap-3">
          <div className="grid h-11 w-11 shrink-0 place-items-center rounded-md bg-white text-sky-700 ring-1 ring-slate-200">
            <Icon className="h-5 w-5" />
          </div>
          <div>
            <p className="font-bold text-slate-950">{provider.metadata.label}</p>
            <p className="mt-1 text-sm leading-6 text-slate-500">
              {provider.metadata.description}
            </p>
          </div>
        </div>
        <ProviderStatusBadge
          label={integrationConnectionStateLabel(provider.connectionState)}
          tone={connectionTone}
        />
      </div>

      <div className="flex flex-wrap gap-2">
        <ProviderStatusBadge
          label={integrationConnectionWorkflowStatusLabel(workflow.status)}
          tone={getWorkflowTone(workflow.status)}
        />
        <ProviderStatusBadge
          label={integrationReadinessStateLabel(provider.readinessState)}
          tone={readinessTone}
        />
        <ProviderStatusBadge
          label={provider.metadata.supportsOAuth ? "OAuth ready" : "API/Webhook"}
          tone="blue"
        />
        {provider.metadata.supportsWebhooks ? (
          <ProviderStatusBadge label="Webhooks" tone="blue" />
        ) : null}
      </div>

      <ProviderCapabilityPills provider={provider} />

      <div className="grid gap-3 md:grid-cols-2">
        <ProviderHealthIndicator provider={provider} />
        <ProviderSyncIndicator provider={provider} />
      </div>

      <div className="rounded-lg border border-slate-200 bg-white p-3">
        <p className="text-xs font-semibold uppercase text-slate-500">
          Connection Summary
        </p>
        <p className="mt-2 text-sm leading-6 text-slate-600">
          {provider.connectionSummary}
        </p>
      </div>

      <div className="flex flex-wrap gap-2 border-t border-slate-200 pt-3">
        {workflow.availableActions.map((action) => (
          <ProviderActionButton
            key={action}
            action={action}
            onClick={() => onOpenWorkflow(provider.metadata.id, action)}
          />
        ))}
      </div>
    </article>
  );
}

function IntegrationCenterSection({
  providers,
  onOpenIntegrations,
  onOpenWorkflow,
}: {
  providers: IntegrationProviderReadiness[];
  onOpenIntegrations: () => void;
  onOpenWorkflow: (
    providerId: IntegrationProviderId,
    action: IntegrationConnectionAction,
  ) => void;
}) {
  const connectedCount = providers.filter(
    (provider) => provider.connectionState === "connected",
  ).length;
  const readyCount = providers.filter(
    (provider) => provider.readinessState === "ready",
  ).length;
  const needsConfigurationCount = providers.filter(
    (provider) => provider.readinessState === "requires_configuration",
  ).length;
  const needsAttentionCount = providers.filter(
    (provider) => provider.healthState === "needs_attention",
  ).length;

  return (
    <section
      className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm"
      data-testid="integration-center"
    >
      <div className="flex flex-col gap-4 xl:flex-row xl:items-start xl:justify-between">
        <div>
          <p className="text-sm font-semibold uppercase text-sky-700">
            Integration Center
          </p>
          <h2 className="mt-1 text-xl font-bold text-slate-950">
            Provider readiness foundation
          </h2>
          <p className="mt-1 max-w-3xl text-sm leading-6 text-slate-500">
            A provider-agnostic registry for communications, lead intake,
            calendar, automation, webhooks, photos, documents, AI, and future
            integrations. No provider is connected or messaged from this center.
          </p>
        </div>
        <button
          type="button"
          onClick={onOpenIntegrations}
          className="inline-flex items-center justify-center gap-2 rounded-md border border-slate-300 bg-white px-3 py-2 text-sm font-semibold text-slate-700 transition hover:bg-slate-50"
        >
          <Activity className="h-4 w-4" />
          Open integration tools
        </button>
      </div>

      <div className="mt-5 grid gap-3 md:grid-cols-4">
        <ProfileStat label="Providers" value={providers.length} />
        <ProfileStat label="Connected" value={connectedCount} />
        <ProfileStat label="Ready" value={readyCount} />
        <ProfileStat
          label="Needs config"
          value={needsConfigurationCount + needsAttentionCount}
        />
      </div>

      <div className="mt-5 grid gap-3 lg:grid-cols-[minmax(0,1fr)_minmax(280px,360px)]">
        <IntegrationNoticeBanner title="No Live Connectivity" tone="blue">
          Connection wizards, configuration pages, validation checks, reconnect,
          and disconnect flows are architecture-ready only. They do not call
          provider APIs, store credentials, send messages, or start sync jobs.
        </IntegrationNoticeBanner>
        <ProviderWorkflowStatusLegend />
      </div>

      <div className="mt-5">
        <TwilioLiveFoundationPanel />
      </div>

      <div className="mt-5">
        <GoHighLevelLiveSyncFoundationPanel />
      </div>

      <div className="mt-5">
        <WebsiteLeadCaptureFoundationPanel />
      </div>

      <div className="mt-5">
        <YelpLeadCaptureFoundationPanel />
      </div>

      <div className="mt-5 grid gap-4 xl:grid-cols-2">
        {providers.map((provider) => (
          <IntegrationProviderCard
            key={provider.metadata.id}
            provider={provider}
            onOpenWorkflow={onOpenWorkflow}
          />
        ))}
      </div>
    </section>
  );
}

function SettingsView({
  snapshot,
  onViewChange,
}: {
  snapshot: CrmSnapshot;
  onViewChange: (view: WorkspaceView) => void;
}) {
  const workflowSettingsByCompany = new Map(
    snapshot.companyWorkflowSettings.map((settings) => [settings.company_id, settings]),
  );
  const integrationProviders = buildIntegrationCenterProviders(snapshot);
  const [connectionDialog, setConnectionDialog] = useState<{
    providerId: IntegrationProviderId;
    action: IntegrationConnectionAction;
  } | null>(null);
  const selectedProvider = connectionDialog
    ? integrationProviders.find((provider) => provider.metadata.id === connectionDialog.providerId)
    : null;
  const selectedWorkflow = selectedProvider
    ? buildIntegrationConnectionWorkflow(selectedProvider)
    : null;

  return (
    <div className="space-y-5">
      <IntegrationCenterSection
        providers={integrationProviders}
        onOpenIntegrations={() => onViewChange("integrations")}
        onOpenWorkflow={(providerId, action) =>
          setConnectionDialog({ providerId, action })
        }
      />

      {selectedWorkflow && connectionDialog ? (
        <IntegrationConnectionDialog
          workflow={selectedWorkflow}
          action={connectionDialog.action}
          onClose={() => setConnectionDialog(null)}
        />
      ) : null}

      <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm">
        <h2 className="text-xl font-bold text-slate-950">Multi-company settings</h2>
        <p className="mt-1 text-sm text-slate-500">
          One shared platform with company-specific workflows for WeatherTech Roofing and IHC Painting.
        </p>
        <div className="mt-5 grid gap-4 lg:grid-cols-2">
          {snapshot.companies.map((company) => {
            const workflow = workflowSettingsByCompany.get(company.id);
            const memberships = snapshot.companyMemberships.filter(
              (membership) => membership.company_id === company.id,
            );
            const templateCount = snapshot.scopeTemplates.filter(
              (template) => template.company_id === company.id,
            ).length;

            return (
              <div key={company.id} className="rounded-lg border border-slate-200 p-4">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-3">
                    <div
                      className="grid h-10 w-10 place-items-center rounded-md font-bold text-white"
                      style={{ backgroundColor: getCompanyBrandColor(company) }}
                    >
                      {companyInitials(company)}
                    </div>
                    <div>
                      <p className="font-semibold text-slate-950">{company.name}</p>
                      <p className="text-sm capitalize text-slate-500">
                        {company.short_name ?? company.trade}
                      </p>
                    </div>
                  </div>
                  {company.trade === "painting" ? (
                    <Paintbrush className="h-5 w-5 text-sky-600" />
                  ) : (
                    <Home className="h-5 w-5 text-sky-600" />
                  )}
                </div>

                <div className="mt-4 grid gap-3 sm:grid-cols-3">
                  <ProfileStat
                    label="Workflow"
                    value={workflow?.workflow_profile ?? company.workflow_profile}
                  />
                  <ProfileStat label="Users" value={memberships.length} />
                  <ProfileStat label="Templates" value={templateCount} />
                </div>

                <div className="mt-4 rounded-lg border border-slate-200 bg-slate-50 p-3">
                  <p className="text-sm font-bold text-slate-950">Workflow terms</p>
                  <p className="mt-2 text-sm text-slate-600">
                    {workflow?.estimate_terms ?? "No estimate terms configured."}
                  </p>
                  <div className="mt-3 grid gap-1">
                    {(workflow?.production_checklist ?? []).slice(0, 5).map((item) => (
                      <p key={item} className="text-sm text-slate-500">
                        - {item}
                      </p>
                    ))}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      <section className="rounded-lg border border-slate-200 bg-white p-5 shadow-sm">
        <h3 className="text-lg font-bold text-slate-950">Shared access model</h3>
        <p className="mt-1 text-sm text-slate-500">
          Users authenticate once and can receive company-level permissions through memberships.
        </p>
        <div className="mt-5 grid gap-3 md:grid-cols-3">
          <ProfileStat label="Companies" value={snapshot.companies.length} />
          <ProfileStat label="Memberships" value={snapshot.companyMemberships.length} />
          <ProfileStat label="Workflow profiles" value={snapshot.companyWorkflowSettings.length} />
        </div>
        <div className="mt-5 rounded-lg border border-slate-200 bg-slate-50 p-4 text-sm text-slate-600">
          Supabase environment variables are configured. CRM, calendar, photos,
          documents, integrations, users, and permission records share the same
          database while company context scopes each workflow.
        </div>
      </section>
    </div>
  );
}

function LeadMiniCard({
  lead,
  company,
}: {
  lead: LeadRecord;
  company?: CompanyRecord;
}) {
  return (
    <div className="rounded-lg border border-slate-200 bg-slate-50 p-4">
      <div className="flex items-start justify-between gap-3">
        <div>
          <p className="font-semibold text-slate-950">{lead.contact_name}</p>
          <p className="mt-1 text-sm text-slate-500">{company?.name}</p>
        </div>
        <Badge label={lead.priority} tone="amber" />
      </div>
      <div className="mt-3 flex items-center justify-between text-sm">
        <span className="text-slate-500">{lead.next_follow_up ?? "No date"}</span>
        <span className="font-semibold text-slate-950">
          {formatMoney(lead.estimated_value)}
        </span>
      </div>
    </div>
  );
}

function ContactLine({
  icon: Icon,
  value,
}: {
  icon: typeof Phone;
  value: string | null;
}) {
  if (!value) {
    return null;
  }

  return (
    <div className="flex items-center gap-2">
      <Icon className="h-4 w-4 text-slate-400" />
      <span>{value}</span>
    </div>
  );
}

function ToastViewport({ notice, error }: { notice: string; error: string }) {
  if (!notice && !error) {
    return null;
  }

  return (
    <div
      aria-live="polite"
      className="fixed right-4 top-4 z-50 grid w-[calc(100%-2rem)] max-w-sm gap-2"
    >
      {notice ? <Toast tone="success" message={notice} /> : null}
      {error ? <Toast tone="error" message={error} /> : null}
    </div>
  );
}

function Toast({ tone, message }: { tone: "success" | "error"; message: string }) {
  return (
    <div
      className={`rounded-lg border px-4 py-3 text-sm font-semibold shadow-xl backdrop-blur ${
        tone === "success"
          ? "border-emerald-200 bg-emerald-50/95 text-emerald-800"
          : "border-red-200 bg-red-50/95 text-red-800"
      }`}
    >
      <div className="flex items-start gap-3">
        {tone === "success" ? (
          <CheckCircle2 className="mt-0.5 h-4 w-4 shrink-0" />
        ) : (
          <ShieldCheck className="mt-0.5 h-4 w-4 shrink-0" />
        )}
        <span>{message}</span>
      </div>
    </div>
  );
}

function Badge({ label, tone }: { label: string; tone: "blue" | "green" | "amber" }) {
  const toneClass = {
    amber: "bg-amber-100 text-amber-800",
    blue: "bg-sky-100 text-sky-800",
    green: "bg-emerald-100 text-emerald-800",
  }[tone];

  return (
    <span
      className={`inline-flex w-fit rounded-md px-2.5 py-1 text-xs font-semibold capitalize ${toneClass}`}
    >
      {label.replace("_", " ")}
    </span>
  );
}

function Message({ tone, message }: { tone: "success" | "error"; message: string }) {
  return (
    <div
      className={`mt-4 rounded-md border px-4 py-3 text-sm font-medium ${
        tone === "success"
          ? "border-emerald-200 bg-emerald-50 text-emerald-800"
          : "border-red-200 bg-red-50 text-red-800"
      }`}
    >
      {message}
    </div>
  );
}

function EmptyState({ label }: { label: string }) {
  return (
    <div className="grid place-items-center rounded-lg border border-dashed border-slate-300 bg-slate-50 p-8 text-center">
      <div>
        <div className="mx-auto grid h-10 w-10 place-items-center rounded-md bg-sky-100 text-sky-700">
          <Search className="h-5 w-5" />
        </div>
        <p className="mt-3 text-sm font-semibold text-slate-600">{label}</p>
      </div>
    </div>
  );
}

function PaginationControls({
  page,
  pageCount,
  total,
  onPageChange,
}: {
  page: number;
  pageCount: number;
  total: number;
  onPageChange: (page: number) => void;
}) {
  if (pageCount <= 1) {
    return null;
  }

  return (
    <div className="flex flex-col gap-3 border-t border-slate-200 px-5 py-4 text-sm sm:flex-row sm:items-center sm:justify-between">
      <span className="font-medium text-slate-500">
        Page {page} of {pageCount} - {total} records
      </span>
      <div className="flex gap-2">
        <button
          type="button"
          onClick={() => onPageChange(Math.max(page - 1, 1))}
          disabled={page === 1}
          className="rounded-md border border-slate-300 bg-white px-3 py-2 font-semibold text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50"
        >
          Previous
        </button>
        <button
          type="button"
          onClick={() => onPageChange(Math.min(page + 1, pageCount))}
          disabled={page === pageCount}
          className="rounded-md border border-slate-300 bg-white px-3 py-2 font-semibold text-slate-700 hover:bg-slate-50 disabled:cursor-not-allowed disabled:opacity-50"
        >
          Next
        </button>
      </div>
    </div>
  );
}

function usePagination<T>(items: T[], pageSize = 8) {
  const [page, setPage] = useState(1);
  const pageCount = Math.max(Math.ceil(items.length / pageSize), 1);
  const effectivePage = Math.min(page, pageCount);

  return {
    page: effectivePage,
    pageCount,
    setPage,
    pagedItems: items.slice((effectivePage - 1) * pageSize, effectivePage * pageSize),
  };
}
